    /**
     * Añade un bloque a una página
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function add_block( $request ) {
        $post_id = absint( $request->get_param( 'id' ) );
        $block_type = $request->get_param( 'type' );
        $block_data = $request->get_param( 'data' );
        $position = $request->get_param( 'position' );

        $post = get_post( $post_id );
        if ( ! $post ) {
            return new WP_REST_Response( array( 'error' => 'Página no encontrada' ), 404 );
        }

        $vbp_data = get_post_meta( $post_id, '_flavor_vbp_data', true ) ?: array(
            'version'  => '2.0.15',
            'elements' => array(),
            'settings' => array(),
        );

        // Crear elemento
        $element_id = 'el_' . bin2hex( random_bytes( 6 ) );
        $elemento = array(
            'id'       => $element_id,
            'type'     => $block_type,
            'name'     => ucfirst( str_replace( '_', ' ', $block_type ) ),
            'visible'  => true,
            'locked'   => false,
            'data'     => $block_data ?: array(),
            'styles'   => $this->get_default_styles(),
            'children' => array(),
        );

        // Insertar en posición
        if ( 'start' === $position ) {
            array_unshift( $vbp_data['elements'], $elemento );
        } elseif ( 'end' === $position ) {
            $vbp_data['elements'][] = $elemento;
        } else {
            $pos = absint( $position );
            array_splice( $vbp_data['elements'], $pos, 0, array( $elemento ) );
        }

        update_post_meta( $post_id, '_flavor_vbp_data', $vbp_data );

        return new WP_REST_Response( array(
            'success'    => true,
            'element_id' => $element_id,
            'block_type' => $block_type,
        ), 201 );
    }

    /**
     * Lista páginas VBP
     *
     * Fase 2: Soporta múltiples post_types (flavor_landing, page, post).
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function list_pages( $request ) {
        $status = $request->get_param( 'status' );
        $post_type_param = $request->get_param( 'post_type' );

        // Fase 2: Determinar post_types a consultar
        if ( ! empty( $post_type_param ) && 'all' !== $post_type_param ) {
            // Si se especifica un tipo específico, validar que esté soportado
            if ( ! $this->is_supported_post_type( $post_type_param ) ) {
                return new WP_REST_Response( array(
                    'success'         => false,
                    'error'           => 'Post type no soportado: ' . $post_type_param,
                    'supported_types' => $this->supported_post_types,
                ), 400 );
            }
            $query_post_types = $post_type_param;
        } else {
            // Por defecto, consultar todos los tipos soportados
            $query_post_types = $this->supported_post_types;
        }

        $args = array(
            'post_type'      => $query_post_types,
            'posts_per_page' => 50,
            'orderby'        => 'modified',
            'order'          => 'DESC',
            // Solo traer posts que tengan datos VBP
            'meta_query'     => array(
                array(
                    'key'     => '_flavor_vbp_data',
                    'compare' => 'EXISTS',
                ),
            ),
        );

        if ( 'any' !== $status ) {
            $args['post_status'] = $status;
        } else {
            $args['post_status'] = array( 'publish', 'draft', 'pending' );
        }

        $pages = get_posts( $args );
        $result = array();

        foreach ( $pages as $page ) {
            $vbp_data = get_post_meta( $page->ID, '_flavor_vbp_data', true );
            $result[] = array(
                'id'             => $page->ID,
                'title'          => $page->post_title,
                'post_type'      => $page->post_type, // Fase 2: incluir tipo de post
                'status'         => $page->post_status,
                'modified'       => $page->post_modified,
                'elements_count' => count( $vbp_data['elements'] ?? array() ),
                'edit_url'       => admin_url( "admin.php?page=vbp-editor&post_id={$page->ID}" ),
                'permalink'      => get_permalink( $page->ID ),
            );
        }

        return new WP_REST_Response( array(
            'success'         => true,
            'total'           => count( $result ),
            'post_types'      => is_array( $query_post_types ) ? $query_post_types : array( $query_post_types ),
            'supported_types' => $this->supported_post_types,
            'pages'           => $result,
        ), 200 );
    }

    /**
     * Genera una sección con contenido plantilla
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function generate_section( $request ) {
        $type = $request->get_param( 'type' );
        $context = $request->get_param( 'context' );

        $section = $this->create_section( $type, $context );

        if ( ! $section ) {
            return new WP_REST_Response( array( 'error' => 'Tipo de sección no válido' ), 400 );
        }

        return new WP_REST_Response( $section, 200 );
    }

    /**
     * Lista las plantillas de página disponibles
     *
     * @return WP_REST_Response
     */
    public function list_templates() {
        $templates = $this->get_all_templates();
        $result = array();

        foreach ( $templates as $slug => $template ) {
            $result[] = array(
                'slug'        => $slug,
                'name'        => $template['name'],
                'description' => $template['description'],
                'industry'    => $template['industry'],
                'sections'    => $template['sections'],
            );
        }

        return new WP_REST_Response( $result, 200 );
    }

    /**
     * Obtiene los presets de un bloque
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function get_block_presets( $request ) {
        $block_type = $request->get_param( 'type' );

        if ( ! $this->ensure_vbp_loaded() ) {
            return new WP_REST_Response( array( 'error' => 'VBP no disponible' ), 500 );
        }

        $libreria = Flavor_VBP_Block_Library::get_instance();
        $bloque = $libreria->get_bloque( $block_type );

        if ( ! $bloque ) {
            return new WP_REST_Response( array( 'error' => 'Bloque no encontrado' ), 404 );
        }

        $presets = array();
        if ( ! empty( $bloque['presets'] ) ) {
            foreach ( $bloque['presets'] as $preset_id => $preset ) {
                $presets[] = array(
                    'id'   => $preset_id,
                    'name' => $preset['name'] ?? $preset_id,
                    'data' => $preset['data'] ?? array(),
                );
            }
        }

        return new WP_REST_Response( array(
            'block_type' => $block_type,
            'presets'    => $presets,
        ), 200 );
    }

    /**
     * Duplica una página VBP
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function duplicate_page( $request ) {
        $post_id = absint( $request->get_param( 'id' ) );
        $new_title = $request->get_param( 'title' );
        $new_slug = $request->get_param( 'slug' );
        $status = $request->get_param( 'status' ) ?: 'draft';
        $copy_meta = $request->get_param( 'copy_meta' ) !== false;

        $post = get_post( $post_id );
        if ( ! $post ) {
            return new WP_REST_Response( array( 'error' => 'Página no encontrada' ), 404 );
        }

        // Preparar título y slug
        if ( empty( $new_title ) ) {
            $new_title = sprintf( __( 'Copia de %s', 'flavor-chat-ia' ), $post->post_title );
        }
        if ( empty( $new_slug ) ) {
            $new_slug = sanitize_title( $new_title );
        }

        // Crear nuevo post duplicado
        $new_post_id = wp_insert_post( array(
            'post_title'   => $new_title,
            'post_name'    => wp_unique_post_slug( $new_slug, 0, $status, $post->post_type, 0 ),
            'post_content' => $post->post_content,
            'post_excerpt' => $post->post_excerpt,
            'post_type'    => $post->post_type,
            'post_status'  => $status,
            'post_author'  => get_current_user_id(),
            'post_parent'  => $post->post_parent,
            'menu_order'   => $post->menu_order,
        ) );

        if ( is_wp_error( $new_post_id ) ) {
            return new WP_REST_Response( array( 'error' => $new_post_id->get_error_message() ), 500 );
        }

        // Copiar meta datos VBP
        $vbp_data = get_post_meta( $post_id, '_flavor_vbp_data', true );
        $vbp_version = get_post_meta( $post_id, '_flavor_vbp_version', true );
        $vbp_elements = get_post_meta( $post_id, '_flavor_vbp_elements', true );
        $vbp_styles = get_post_meta( $post_id, '_flavor_vbp_styles', true );
        $vbp_config = get_post_meta( $post_id, '_flavor_vbp_config', true );

        if ( $vbp_data ) {
            // Regenerar IDs de elementos para evitar conflictos
            if ( ! empty( $vbp_data['elements'] ) ) {
                $vbp_data['elements'] = $this->regenerate_element_ids( $vbp_data['elements'] );
            }
            update_post_meta( $new_post_id, '_flavor_vbp_data', $vbp_data );
        }
        if ( $vbp_version ) {
            update_post_meta( $new_post_id, '_flavor_vbp_version', $vbp_version );
        }
        if ( ! empty( $vbp_elements ) ) {
            $new_elements = $this->regenerate_element_ids( $vbp_elements );
            update_post_meta( $new_post_id, '_flavor_vbp_elements', $new_elements );
        }
        if ( ! empty( $vbp_styles ) ) {
            update_post_meta( $new_post_id, '_flavor_vbp_styles', $vbp_styles );
        }
        if ( ! empty( $vbp_config ) ) {
            update_post_meta( $new_post_id, '_flavor_vbp_config', $vbp_config );
        }

        // Copiar metadatos SEO si se solicita
        if ( $copy_meta ) {
            $meta_keys_to_copy = array(
                '_flavor_seo_title',
                '_flavor_seo_description',
                '_flavor_seo_keywords',
                '_yoast_wpseo_title',
                '_yoast_wpseo_metadesc',
                '_yoast_wpseo_focuskw',
                '_thumbnail_id',
            );

            foreach ( $meta_keys_to_copy as $meta_key ) {
                $meta_value = get_post_meta( $post_id, $meta_key, true );
                if ( ! empty( $meta_value ) ) {
                    update_post_meta( $new_post_id, $meta_key, $meta_value );
                }
            }
        }

        // Marcar como copia
        update_post_meta( $new_post_id, '_flavor_duplicated_from', $post_id );
        update_post_meta( $new_post_id, '_flavor_duplicated_date', current_time( 'mysql' ) );

        return new WP_REST_Response( array(
            'success'     => true,
            'id'          => $new_post_id,
            'original_id' => $post_id,
            'title'       => get_the_title( $new_post_id ),
            'slug'        => get_post_field( 'post_name', $new_post_id ),
            'status'      => $status,
            'url'         => get_permalink( $new_post_id ),
            'edit_url'    => admin_url( "admin.php?page=vbp-editor&post_id={$new_post_id}" ),
            'meta_copied' => $copy_meta,
        ), 201 );
    }

    /**
     * Regenera IDs de elementos recursivamente
     *
     * @param array $elements Elementos.
     * @return array
     */
    private function regenerate_element_ids( $elements ) {
        foreach ( $elements as &$element ) {
            $element['id'] = 'el_' . bin2hex( random_bytes( 6 ) );
            if ( ! empty( $element['children'] ) ) {
                $element['children'] = $this->regenerate_element_ids( $element['children'] );
            }
        }
        return $elements;
    }

