    /**
     * Crea múltiples páginas VBP en una sola petición
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function bulk_create_pages( $request ) {
        $pages_data = $request->get_param( 'pages' );
        $default_preset = sanitize_key( $request->get_param( 'default_preset' ) );
        $default_status = sanitize_key( $request->get_param( 'default_status' ) );

        if ( empty( $pages_data ) || ! is_array( $pages_data ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Se requiere un array de páginas',
            ), 400 );
        }

        $created_pages = array();
        $errors = array();
        $start_time = microtime( true );

        foreach ( $pages_data as $index => $page_config ) {
            $title = sanitize_text_field( $page_config['title'] ?? '' );

            if ( empty( $title ) ) {
                $errors[] = array(
                    'index' => $index,
                    'error' => 'El título es requerido',
                );
                continue;
            }

            $preset = sanitize_key( $page_config['preset'] ?? $default_preset );
            $status = sanitize_key( $page_config['status'] ?? $default_status );
            $sections = $page_config['sections'] ?? array( 'hero', 'features', 'cta' );
            $context = $page_config['context'] ?? array();
            $slug = sanitize_title( $page_config['slug'] ?? $title );

            // Generar elementos desde las secciones
            $elements = array();
            foreach ( $sections as $section_type ) {
                $section_data = $this->create_section( $section_type, $context );
                if ( $section_data ) {
                    $elements[] = array(
                        'type' => $section_type,
                        'data' => $section_data,
                    );
                }
            }

            // Preparar elementos
            $elements = $this->prepare_elements( $elements );

            // Crear post
            $post_id = wp_insert_post( array(
                'post_title'  => $title,
                'post_name'   => $slug,
                'post_type'   => 'flavor_landing',
                'post_status' => $status,
            ) );

            if ( is_wp_error( $post_id ) ) {
                $errors[] = array(
                    'index' => $index,
                    'title' => $title,
                    'error' => $post_id->get_error_message(),
                );
                continue;
            }

            // Obtener preset de diseño
            $preset_settings = $this->get_design_preset( $preset );
            $settings = array(
                'pageWidth'       => 1200,
                'backgroundColor' => '#ffffff',
                'design_preset'   => $preset,
            );

            if ( $preset_settings ) {
                $settings = array_merge( $settings, $preset_settings );
            }

            // Guardar datos VBP
            $vbp_data = array(
                'version'  => '2.0.15',
                'elements' => $elements,
                'settings' => $settings,
            );

            update_post_meta( $post_id, '_flavor_vbp_data', $vbp_data );
            update_post_meta( $post_id, '_flavor_vbp_version', '2.0.15' );

            $created_pages[] = array(
                'index'    => $index,
                'id'       => $post_id,
                'title'    => $title,
                'slug'     => get_post_field( 'post_name', $post_id ),
                'status'   => $status,
                'preset'   => $preset,
                'sections' => count( $elements ),
                'edit_url' => admin_url( "admin.php?page=vbp-editor&post_id={$post_id}" ),
                'view_url' => get_permalink( $post_id ),
            );
        }

        $elapsed_time = round( ( microtime( true ) - $start_time ) * 1000, 2 );

        return new WP_REST_Response( array(
            'success'       => count( $errors ) === 0,
            'created_count' => count( $created_pages ),
            'error_count'   => count( $errors ),
            'pages'         => $created_pages,
            'errors'        => $errors,
            'elapsed_ms'    => $elapsed_time,
        ), count( $created_pages ) > 0 ? 201 : 400 );
    }

    /**
     * Exporta una página VBP como plantilla JSON
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function export_template( $request ) {
        $page_id = (int) $request->get_param( 'id' );
        $post = get_post( $page_id );

        if ( ! $this->is_valid_vbp_post( $post ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Página VBP no encontrada',
            ), 404 );
        }

        $vbp_data = get_post_meta( $page_id, '_flavor_vbp_data', true );

        if ( empty( $vbp_data ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'La página no tiene contenido VBP',
            ), 400 );
        }

        $template = array(
            'version'     => '1.0',
            'exported_at' => current_time( 'c' ),
            'source_id'   => $page_id,
            'source_site' => home_url(),
            'title'       => $post->post_title,
            'slug'        => $post->post_name,
            'vbp_version' => $vbp_data['version'] ?? '2.0.15',
            'elements'    => $vbp_data['elements'] ?? array(),
            'settings'    => $vbp_data['settings'] ?? array(),
            'meta'        => array(
                'sections_count' => count( $vbp_data['elements'] ?? array() ),
                'preset'         => $vbp_data['settings']['design_preset'] ?? 'custom',
            ),
        );

        return new WP_REST_Response( array(
            'success'  => true,
            'template' => $template,
        ), 200 );
    }

    /**
     * Importa una plantilla JSON como nueva página VBP
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function import_template( $request ) {
        $template = $request->get_param( 'template' );
        $custom_title = sanitize_text_field( $request->get_param( 'title' ) );
        $status = sanitize_key( $request->get_param( 'status' ) );

        if ( empty( $template ) || ! is_array( $template ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Datos de plantilla inválidos',
            ), 400 );
        }

        // Extraer datos de la plantilla
        $title = ! empty( $custom_title ) ? $custom_title : ( $template['title'] ?? 'Página Importada' );
        $elements = $template['elements'] ?? array();
        $settings = $template['settings'] ?? array();

        if ( empty( $elements ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'La plantilla no contiene elementos',
            ), 400 );
        }

        // Regenerar IDs para evitar conflictos
        $elements = $this->regenerate_element_ids( $elements );

        // Crear post
        $post_id = wp_insert_post( array(
            'post_title'  => $title,
            'post_type'   => 'flavor_landing',
            'post_status' => $status,
        ) );

        if ( is_wp_error( $post_id ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => $post_id->get_error_message(),
            ), 500 );
        }

        // Guardar datos VBP
        $vbp_data = array(
            'version'  => '2.0.15',
            'elements' => $elements,
            'settings' => $settings,
        );

        update_post_meta( $post_id, '_flavor_vbp_data', $vbp_data );
        update_post_meta( $post_id, '_flavor_vbp_version', '2.0.15' );
        update_post_meta( $post_id, '_flavor_imported_from', $template['source_site'] ?? 'unknown' );
        update_post_meta( $post_id, '_flavor_imported_at', current_time( 'mysql' ) );

        return new WP_REST_Response( array(
            'success'        => true,
            'id'             => $post_id,
            'title'          => $title,
            'status'         => $status,
            'sections_count' => count( $elements ),
            'imported_from'  => $template['source_site'] ?? 'unknown',
            'edit_url'       => admin_url( "admin.php?page=vbp-editor&post_id={$post_id}" ),
            'view_url'       => get_permalink( $post_id ),
        ), 201 );
    }

    /**
     * Clona una página VBP desde un sitio remoto
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function clone_remote_template( $request ) {
        $source_url = esc_url_raw( $request->get_param( 'source_url' ) );
        $page_id = (int) $request->get_param( 'page_id' );
        $remote_api_key = sanitize_text_field( $request->get_param( 'api_key' ) );
        $custom_title = sanitize_text_field( $request->get_param( 'title' ) );
        $status = sanitize_key( $request->get_param( 'status' ) );

        // Validar URL
        if ( empty( $source_url ) || ! filter_var( $source_url, FILTER_VALIDATE_URL ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'URL de origen inválida',
            ), 400 );
        }

        // Construir endpoint remoto
        $export_endpoint = trailingslashit( $source_url ) . 'wp-json/flavor-vbp/v1/claude/templates/export/' . $page_id;

        // Hacer petición al sitio remoto
        $response = wp_remote_get( $export_endpoint, array(
            'headers' => array(
                'X-VBP-Key' => $remote_api_key,
            ),
            'timeout' => 30,
        ) );

        if ( is_wp_error( $response ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Error al conectar con el sitio remoto: ' . $response->get_error_message(),
            ), 502 );
        }

        $response_code = wp_remote_retrieve_response_code( $response );
        if ( $response_code !== 200 ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'El sitio remoto devolvió error: ' . $response_code,
            ), $response_code );
        }

        $body = wp_remote_retrieve_body( $response );
        $data = json_decode( $body, true );

        if ( empty( $data['success'] ) || empty( $data['template'] ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Respuesta inválida del sitio remoto',
            ), 502 );
        }

        $template = $data['template'];

        // Usar el método de importación existente
        $import_request = new WP_REST_Request( 'POST' );
        $import_request->set_param( 'template', $template );
        $import_request->set_param( 'title', $custom_title ?: $template['title'] );
        $import_request->set_param( 'status', $status );

        $result = $this->import_template( $import_request );
        $result_data = $result->get_data();

        if ( ! empty( $result_data['success'] ) ) {
            $result_data['cloned_from'] = array(
                'url'     => $source_url,
                'page_id' => $page_id,
            );
        }

        return new WP_REST_Response( $result_data, $result->get_status() );
    }

    /**
     * Genera preview HTML de elementos VBP sin guardar
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function preview_page( $request ) {
        $elements = $request->get_param( 'elements' );
        $preset = sanitize_key( $request->get_param( 'preset' ) );
        $settings = $request->get_param( 'settings' );

        if ( empty( $elements ) || ! is_array( $elements ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Se requieren elementos para el preview',
            ), 400 );
        }

        // Cargar VBP Canvas si está disponible
        if ( ! class_exists( 'Flavor_VBP_Canvas' ) ) {
            $canvas_path = FLAVOR_CHAT_IA_PATH . 'includes/visual-builder-pro/class-vbp-canvas.php';
            if ( file_exists( $canvas_path ) ) {
                require_once $canvas_path;
            }
        }

        // Preparar elementos
        $elements = $this->prepare_elements( $elements );

        // Obtener preset de diseño
        $preset_settings = $this->get_design_preset( $preset );
        $final_settings = array_merge(
            array(
                'pageWidth'       => 1200,
                'backgroundColor' => '#ffffff',
                'design_preset'   => $preset,
            ),
            $preset_settings ?: array(),
            $settings ?: array()
        );

        // Generar CSS de preset
        $preset_css = $this->generate_preset_css( $preset_settings );

        // Renderizar HTML
        $html_parts = array();
        if ( class_exists( 'Flavor_VBP_Canvas' ) ) {
            $canvas = Flavor_VBP_Canvas::get_instance();
            foreach ( $elements as $element ) {
                $html_parts[] = $canvas->render_element_public( $element );
            }
        } else {
            // Fallback: renderizado básico
            foreach ( $elements as $element ) {
                $html_parts[] = $this->render_element_basic( $element );
            }
        }

        $preview_html = implode( "\n", $html_parts );

        // Construir HTML completo con estilos
        $full_html = sprintf(
            '<!DOCTYPE html>
<html lang="es">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Preview VBP</title>
    <style>
        * { box-sizing: border-box; margin: 0; padding: 0; }
        body { font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; }
        %s
    </style>
</head>
<body style="background-color: %s;">
    <div class="vbp-preview" style="max-width: %dpx; margin: 0 auto;">
        %s
    </div>
</body>
</html>',
            $preset_css,
            esc_attr( $final_settings['backgroundColor'] ),
            (int) $final_settings['pageWidth'],
            $preview_html
        );

        return new WP_REST_Response( array(
            'success'        => true,
            'html'           => $full_html,
            'elements_count' => count( $elements ),
            'preset'         => $preset,
            'settings'       => $final_settings,
        ), 200 );
    }

    /**
     * Renderizado básico de elemento (fallback)
     *
     * @param array $element Elemento a renderizar.
     * @return string HTML.
     */
    private function render_element_basic( $element ) {
        $type = $element['type'] ?? 'text';
        $data = $element['data'] ?? array();
        $html = '';

        switch ( $type ) {
            case 'hero':
                $html = sprintf(
                    '<section class="vbp-hero" style="padding: 80px 20px; background: %s; color: #fff; text-align: center;">
                        <h1>%s</h1>
                        <p>%s</p>
                    </section>',
                    esc_attr( $data['color_fondo'] ?? '#1a1a2e' ),
                    esc_html( $data['titulo'] ?? '' ),
                    esc_html( $data['subtitulo'] ?? '' )
                );
                break;

            case 'features':
                $items_html = '';
                $items = $data['items'] ?? array();
                foreach ( $items as $item ) {
                    $items_html .= sprintf(
                        '<div style="flex: 1; padding: 20px; text-align: center;">
                            <h3>%s</h3>
                            <p>%s</p>
                        </div>',
                        esc_html( $item['titulo'] ?? '' ),
                        esc_html( $item['descripcion'] ?? '' )
                    );
                }
                $html = sprintf(
                    '<section class="vbp-features" style="padding: 60px 20px;">
                        <h2 style="text-align: center;">%s</h2>
                        <div style="display: flex; flex-wrap: wrap; gap: 20px; margin-top: 40px;">%s</div>
                    </section>',
                    esc_html( $data['titulo'] ?? '' ),
                    $items_html
                );
                break;

            case 'cta':
                $html = sprintf(
                    '<section class="vbp-cta" style="padding: 60px 20px; background: #f5f5f5; text-align: center;">
                        <h2>%s</h2>
                        <p>%s</p>
                        <a href="%s" style="display: inline-block; margin-top: 20px; padding: 12px 30px; background: #333; color: #fff; text-decoration: none; border-radius: 5px;">%s</a>
                    </section>',
                    esc_html( $data['titulo'] ?? '' ),
                    esc_html( $data['subtitulo'] ?? '' ),
                    esc_url( $data['boton_url'] ?? '#' ),
                    esc_html( $data['boton_texto'] ?? 'Contactar' )
                );
                break;

            default:
                $html = sprintf(
                    '<div class="vbp-element vbp-%s" style="padding: 20px;">%s</div>',
                    esc_attr( $type ),
                    esc_html( $data['contenido'] ?? $data['texto'] ?? '' )
                );
        }

        return $html;
    }

    /**
     * Genera CSS de un preset de diseño
     *
     * @param array $preset Preset de diseño.
     * @return string CSS.
     */
    private function generate_preset_css( $preset ) {
        if ( empty( $preset ) ) {
            return '';
        }

        $colors = $preset['colors'] ?? array();
        $css = ':root {';

        foreach ( $colors as $name => $value ) {
            $css .= sprintf( '--vbp-%s: %s;', esc_attr( $name ), esc_attr( $value ) );
        }

        $css .= '}';

        // Añadir tipografía si existe
        if ( ! empty( $preset['typography']['font_family'] ) ) {
            $css .= sprintf(
                'body { font-family: %s; }',
                esc_attr( $preset['typography']['font_family'] )
            );
        }

        return $css;
    }

    /**
     * Analiza SEO de una página VBP
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function analyze_page_seo( $request ) {
        $page_id = (int) $request->get_param( 'id' );
        $post = get_post( $page_id );

        if ( ! $this->is_valid_vbp_post( $post ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Página VBP no encontrada',
            ), 404 );
        }

        $vbp_data = get_post_meta( $page_id, '_flavor_vbp_data', true );
        $elements = $vbp_data['elements'] ?? array();

        // Análisis
        $analysis = array(
            'score'       => 0,
            'max_score'   => 100,
            'issues'      => array(),
            'warnings'    => array(),
            'passed'      => array(),
            'suggestions' => array(),
        );

        // Extraer contenido de texto
        $all_text = $this->extract_text_from_elements( $elements );
        $word_count = str_word_count( $all_text );

        // 1. Título (20 puntos)
        $title = $post->post_title;
        $title_length = mb_strlen( $title );
        if ( $title_length >= 30 && $title_length <= 60 ) {
            $analysis['score'] += 20;
            $analysis['passed'][] = 'Título con longitud óptima (' . $title_length . ' caracteres)';
        } elseif ( $title_length > 0 ) {
            $analysis['score'] += 10;
            $analysis['warnings'][] = 'Título debería tener entre 30-60 caracteres (actual: ' . $title_length . ')';
        } else {
            $analysis['issues'][] = 'Falta título de página';
        }

        // 2. Meta descripción (15 puntos)
        $meta_desc = get_post_meta( $page_id, '_yoast_wpseo_metadesc', true )
            ?: get_post_meta( $page_id, '_flavor_seo_description', true );
        if ( ! empty( $meta_desc ) ) {
            $desc_length = mb_strlen( $meta_desc );
            if ( $desc_length >= 120 && $desc_length <= 160 ) {
                $analysis['score'] += 15;
                $analysis['passed'][] = 'Meta descripción con longitud óptima';
            } else {
                $analysis['score'] += 8;
                $analysis['warnings'][] = 'Meta descripción debería tener 120-160 caracteres';
            }
        } else {
            $analysis['issues'][] = 'Falta meta descripción';
            $analysis['suggestions'][] = $this->generate_meta_description( $all_text );
        }

        // 3. Estructura de encabezados (15 puntos)
        $headings = $this->extract_headings_from_elements( $elements );
        $has_h1 = ! empty( $headings['h1'] );
        $has_h2 = ! empty( $headings['h2'] );

        if ( $has_h1 && count( $headings['h1'] ) === 1 ) {
            $analysis['score'] += 8;
            $analysis['passed'][] = 'Un solo H1 detectado';
        } elseif ( $has_h1 ) {
            $analysis['score'] += 4;
            $analysis['warnings'][] = 'Múltiples H1 detectados (' . count( $headings['h1'] ) . ')';
        } else {
            $analysis['issues'][] = 'Falta encabezado H1';
        }

        if ( $has_h2 ) {
            $analysis['score'] += 7;
            $analysis['passed'][] = 'Encabezados H2 detectados (' . count( $headings['h2'] ) . ')';
        } else {
            $analysis['warnings'][] = 'No hay encabezados H2 para estructurar el contenido';
        }

        // 4. Contenido (20 puntos)
        if ( $word_count >= 300 ) {
            $analysis['score'] += 20;
            $analysis['passed'][] = 'Contenido suficiente (' . $word_count . ' palabras)';
        } elseif ( $word_count >= 150 ) {
            $analysis['score'] += 12;
            $analysis['warnings'][] = 'Contenido algo corto (' . $word_count . ' palabras, recomendado: 300+)';
        } else {
            $analysis['score'] += 5;
            $analysis['issues'][] = 'Contenido muy corto (' . $word_count . ' palabras)';
        }

        // 5. Imágenes con alt (15 puntos)
        $images = $this->extract_images_from_elements( $elements );
        $images_with_alt = array_filter( $images, function( $img ) {
            return ! empty( $img['alt'] );
        } );

        if ( count( $images ) === 0 ) {
            $analysis['warnings'][] = 'No hay imágenes en la página';
        } elseif ( count( $images_with_alt ) === count( $images ) ) {
            $analysis['score'] += 15;
            $analysis['passed'][] = 'Todas las imágenes tienen texto alternativo';
        } else {
            $missing = count( $images ) - count( $images_with_alt );
            $analysis['score'] += 8;
            $analysis['warnings'][] = $missing . ' imagen(es) sin texto alternativo';
        }

        // 6. Enlaces y CTAs (15 puntos)
        $links = $this->extract_links_from_elements( $elements );
        $cta_count = count( array_filter( $links, function( $link ) {
            return ! empty( $link['is_cta'] );
        } ) );

        if ( $cta_count > 0 ) {
            $analysis['score'] += 15;
            $analysis['passed'][] = 'CTAs detectados (' . $cta_count . ')';
        } else {
            $analysis['warnings'][] = 'No se detectaron llamadas a la acción (CTAs)';
        }

        // Calcular calificación
        $percentage = round( ( $analysis['score'] / $analysis['max_score'] ) * 100 );
        if ( $percentage >= 80 ) {
            $analysis['grade'] = 'A';
            $analysis['status'] = 'excellent';
        } elseif ( $percentage >= 60 ) {
            $analysis['grade'] = 'B';
            $analysis['status'] = 'good';
        } elseif ( $percentage >= 40 ) {
            $analysis['grade'] = 'C';
            $analysis['status'] = 'needs_improvement';
        } else {
            $analysis['grade'] = 'D';
            $analysis['status'] = 'poor';
        }

        $analysis['percentage'] = $percentage;

        return new WP_REST_Response( array(
            'success'  => true,
            'page_id'  => $page_id,
            'title'    => $post->post_title,
            'url'      => get_permalink( $page_id ),
            'analysis' => $analysis,
            'meta'     => array(
                'word_count'    => $word_count,
                'images_count'  => count( $images ),
                'links_count'   => count( $links ),
                'headings'      => $headings,
            ),
        ), 200 );
    }

    /**
     * Extrae texto de elementos VBP
     */
    private function extract_text_from_elements( $elements ) {
        $text = '';
        foreach ( $elements as $element ) {
            $data = $element['data'] ?? array();
            $text .= ' ' . ( $data['titulo'] ?? '' );
            $text .= ' ' . ( $data['subtitulo'] ?? '' );
            $text .= ' ' . ( $data['contenido'] ?? '' );
            $text .= ' ' . ( $data['texto'] ?? '' );
            $text .= ' ' . ( $data['descripcion'] ?? '' );

            if ( ! empty( $element['children'] ) ) {
                $text .= ' ' . $this->extract_text_from_elements( $element['children'] );
            }
        }
        return strip_tags( $text );
    }

    /**
     * Extrae encabezados de elementos VBP
     */
    private function extract_headings_from_elements( $elements ) {
        $headings = array( 'h1' => array(), 'h2' => array(), 'h3' => array() );

        foreach ( $elements as $element ) {
            $type = $element['type'] ?? '';
            $data = $element['data'] ?? array();

            // Hero usualmente contiene H1
            if ( $type === 'hero' && ! empty( $data['titulo'] ) ) {
                $headings['h1'][] = $data['titulo'];
            }

            // Secciones con título son H2
            if ( in_array( $type, array( 'features', 'testimonials', 'pricing', 'faq', 'cta', 'team', 'stats' ), true ) ) {
                if ( ! empty( $data['titulo'] ) ) {
                    $headings['h2'][] = $data['titulo'];
                }
            }

            if ( ! empty( $element['children'] ) ) {
                $child_headings = $this->extract_headings_from_elements( $element['children'] );
                foreach ( $child_headings as $level => $texts ) {
                    $headings[ $level ] = array_merge( $headings[ $level ], $texts );
                }
            }
        }

        return $headings;
    }

    /**
     * Extrae imágenes de elementos VBP
     */
    private function extract_images_from_elements( $elements ) {
        $images = array();

        foreach ( $elements as $element ) {
            $data = $element['data'] ?? array();

            if ( ! empty( $data['imagen'] ) ) {
                $images[] = array(
                    'src' => $data['imagen'],
                    'alt' => $data['imagen_alt'] ?? '',
                );
            }
            if ( ! empty( $data['imagen_fondo'] ) ) {
                $images[] = array(
                    'src' => $data['imagen_fondo'],
                    'alt' => $data['imagen_fondo_alt'] ?? '',
                );
            }

            if ( ! empty( $element['children'] ) ) {
                $images = array_merge( $images, $this->extract_images_from_elements( $element['children'] ) );
            }
        }

        return $images;
    }

    /**
     * Extrae enlaces de elementos VBP
     */
    private function extract_links_from_elements( $elements ) {
        $links = array();

        foreach ( $elements as $element ) {
            $data = $element['data'] ?? array();

            if ( ! empty( $data['boton_url'] ) ) {
                $links[] = array(
                    'url'    => $data['boton_url'],
                    'text'   => $data['boton_texto'] ?? '',
                    'is_cta' => true,
                );
            }
            if ( ! empty( $data['enlace'] ) ) {
                $links[] = array(
                    'url'    => $data['enlace'],
                    'text'   => $data['enlace_texto'] ?? '',
                    'is_cta' => false,
                );
            }

            if ( ! empty( $element['children'] ) ) {
                $links = array_merge( $links, $this->extract_links_from_elements( $element['children'] ) );
            }
        }

        return $links;
    }

    /**
     * Genera sugerencia de meta descripción
     */
    private function generate_meta_description( $text ) {
        $text = trim( preg_replace( '/\s+/', ' ', $text ) );
        if ( mb_strlen( $text ) > 160 ) {
            $text = mb_substr( $text, 0, 157 ) . '...';
        }
        return array(
            'type'  => 'meta_description',
            'value' => $text,
        );
    }

    /**
     * Sugiere mejoras SEO para contenido
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function suggest_seo_improvements( $request ) {
        $content = sanitize_textarea_field( $request->get_param( 'content' ) );
        $keywords = $request->get_param( 'keywords' ) ?: array();
        $type = sanitize_key( $request->get_param( 'type' ) );

        $suggestions = array();
        $word_count = str_word_count( $content );

        // Sugerencias de título
        $suggestions['title'] = array(
            'current_length' => mb_strlen( $content ),
            'optimal_range'  => '30-60 caracteres',
            'suggestion'     => $this->generate_title_suggestion( $content, $keywords ),
        );

        // Sugerencias de meta descripción
        $suggestions['meta_description'] = array(
            'optimal_range' => '120-160 caracteres',
            'suggestion'    => $this->generate_meta_description( $content ),
        );

        // Sugerencias de keywords
        if ( ! empty( $keywords ) ) {
            $keyword_density = array();
            foreach ( $keywords as $keyword ) {
                $count = substr_count( strtolower( $content ), strtolower( $keyword ) );
                $density = $word_count > 0 ? round( ( $count / $word_count ) * 100, 2 ) : 0;
                $keyword_density[ $keyword ] = array(
                    'count'   => $count,
                    'density' => $density . '%',
                    'status'  => $density >= 1 && $density <= 3 ? 'optimal' : ( $density < 1 ? 'low' : 'high' ),
                );
            }
            $suggestions['keywords'] = $keyword_density;
        }

        // Sugerencias de estructura
        $suggestions['structure'] = array(
            'word_count'       => $word_count,
            'recommended_min'  => 300,
            'paragraphs'       => substr_count( $content, "\n\n" ) + 1,
            'has_lists'        => strpos( $content, '<ul>' ) !== false || strpos( $content, '<ol>' ) !== false,
        );

        return new WP_REST_Response( array(
            'success'     => true,
            'suggestions' => $suggestions,
            'content_preview' => mb_substr( $content, 0, 200 ) . '...',
        ), 200 );
    }

    /**
     * Genera sugerencia de título
     */
    private function generate_title_suggestion( $content, $keywords ) {
        $words = explode( ' ', trim( $content ) );
        $title = implode( ' ', array_slice( $words, 0, 8 ) );

        if ( ! empty( $keywords[0] ) && stripos( $title, $keywords[0] ) === false ) {
            $title = $keywords[0] . ' - ' . $title;
        }

        if ( mb_strlen( $title ) > 60 ) {
            $title = mb_substr( $title, 0, 57 ) . '...';
        }

        return $title;
    }

    // =========================================================================
    // ANÁLISIS DE ACCESIBILIDAD
    // =========================================================================

    /**
     * Analiza accesibilidad de una página VBP
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function analyze_page_accessibility( $request ) {
        $page_id = (int) $request->get_param( 'id' );
        $post = get_post( $page_id );

        if ( ! $this->is_valid_vbp_post( $post ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Página VBP no encontrada',
            ), 404 );
        }

        $vbp_data = get_post_meta( $page_id, '_flavor_vbp_data', true );
        $elements = $vbp_data['elements'] ?? array();
        $settings = $vbp_data['settings'] ?? array();

        $analysis = array(
            'score'    => 0,
            'max_score'=> 100,
            'level'    => 'AA', // WCAG level objetivo
            'issues'   => array(),
            'warnings' => array(),
            'passed'   => array(),
        );

        // 1. Imágenes con alt (25 puntos)
        $images = $this->extract_images_from_elements( $elements );
        $images_without_alt = array_filter( $images, function( $img ) {
            return empty( $img['alt'] );
        } );

        if ( count( $images ) === 0 ) {
            $analysis['score'] += 25;
            $analysis['passed'][] = 'No hay imágenes que necesiten texto alternativo';
        } elseif ( count( $images_without_alt ) === 0 ) {
            $analysis['score'] += 25;
            $analysis['passed'][] = 'Todas las imágenes tienen texto alternativo';
        } else {
            $analysis['score'] += max( 0, 25 - ( count( $images_without_alt ) * 5 ) );
            $analysis['issues'][] = array(
                'type'    => 'missing_alt',
                'message' => count( $images_without_alt ) . ' imagen(es) sin texto alternativo',
                'wcag'    => '1.1.1',
                'impact'  => 'critical',
            );
        }

        // 2. Contraste de colores (25 puntos)
        $color_issues = $this->check_color_contrast( $elements, $settings );
        if ( empty( $color_issues ) ) {
            $analysis['score'] += 25;
            $analysis['passed'][] = 'Contraste de colores adecuado';
        } else {
            $analysis['score'] += max( 0, 25 - ( count( $color_issues ) * 8 ) );
            foreach ( $color_issues as $issue ) {
                $analysis['warnings'][] = $issue;
            }
        }

        // 3. Estructura de encabezados (20 puntos)
        $headings = $this->extract_headings_from_elements( $elements );
        $heading_issues = $this->check_heading_structure( $headings );

        if ( empty( $heading_issues ) ) {
            $analysis['score'] += 20;
            $analysis['passed'][] = 'Estructura de encabezados correcta';
        } else {
            $analysis['score'] += max( 0, 20 - ( count( $heading_issues ) * 5 ) );
            foreach ( $heading_issues as $issue ) {
                $analysis['issues'][] = $issue;
            }
        }

        // 4. Enlaces accesibles (15 puntos)
        $links = $this->extract_links_from_elements( $elements );
        $link_issues = $this->check_links_accessibility( $links );

        if ( empty( $link_issues ) ) {
            $analysis['score'] += 15;
            $analysis['passed'][] = 'Enlaces accesibles';
        } else {
            $analysis['score'] += max( 0, 15 - ( count( $link_issues ) * 5 ) );
            foreach ( $link_issues as $issue ) {
                $analysis['warnings'][] = $issue;
            }
        }

        // 5. Formularios accesibles (15 puntos)
        $forms = $this->extract_forms_from_elements( $elements );
        $form_issues = $this->check_forms_accessibility( $forms );

        if ( empty( $forms ) ) {
            $analysis['score'] += 15;
            $analysis['passed'][] = 'No hay formularios que revisar';
        } elseif ( empty( $form_issues ) ) {
            $analysis['score'] += 15;
            $analysis['passed'][] = 'Formularios accesibles';
        } else {
            $analysis['score'] += max( 0, 15 - ( count( $form_issues ) * 5 ) );
            foreach ( $form_issues as $issue ) {
                $analysis['issues'][] = $issue;
            }
        }

        // Calcular nivel de conformidad
        $percentage = round( ( $analysis['score'] / $analysis['max_score'] ) * 100 );
        if ( $percentage >= 90 && empty( $analysis['issues'] ) ) {
            $analysis['conformance'] = 'AAA';
            $analysis['status'] = 'excellent';
        } elseif ( $percentage >= 75 ) {
            $analysis['conformance'] = 'AA';
            $analysis['status'] = 'good';
        } elseif ( $percentage >= 50 ) {
            $analysis['conformance'] = 'A';
            $analysis['status'] = 'needs_improvement';
        } else {
            $analysis['conformance'] = 'non-conformant';
            $analysis['status'] = 'poor';
        }

        $analysis['percentage'] = $percentage;

        return new WP_REST_Response( array(
            'success'  => true,
            'page_id'  => $page_id,
            'title'    => $post->post_title,
            'analysis' => $analysis,
        ), 200 );
    }

    /**
     * Verifica contraste de colores
     */
    private function check_color_contrast( $elements, $settings ) {
        $issues = array();
        $bg_color = $settings['backgroundColor'] ?? '#ffffff';

        // Colores comunes a verificar
        $text_colors = array();
        foreach ( $elements as $element ) {
            $data = $element['data'] ?? array();
            if ( ! empty( $data['color'] ) ) {
                $text_colors[] = $data['color'];
            }
            if ( ! empty( $data['color_texto'] ) ) {
                $text_colors[] = $data['color_texto'];
            }
        }

        foreach ( array_unique( $text_colors ) as $text_color ) {
            $ratio = $this->calculate_contrast_ratio( $text_color, $bg_color );
            if ( $ratio < 4.5 ) {
                $issues[] = array(
                    'type'    => 'low_contrast',
                    'message' => "Contraste insuficiente ({$ratio}:1) entre {$text_color} y {$bg_color}",
                    'wcag'    => '1.4.3',
                    'impact'  => 'serious',
                );
            }
        }

        return $issues;
    }

    /**
     * Calcula ratio de contraste entre dos colores
     */
    private function calculate_contrast_ratio( $color1, $color2 ) {
        $l1 = $this->get_relative_luminance( $color1 );
        $l2 = $this->get_relative_luminance( $color2 );

        $lighter = max( $l1, $l2 );
        $darker = min( $l1, $l2 );

        return round( ( $lighter + 0.05 ) / ( $darker + 0.05 ), 2 );
    }

    /**
     * Obtiene luminancia relativa de un color
     */
    private function get_relative_luminance( $hex ) {
        $hex = ltrim( $hex, '#' );
        if ( strlen( $hex ) === 3 ) {
            $hex = $hex[0] . $hex[0] . $hex[1] . $hex[1] . $hex[2] . $hex[2];
        }

        $r = hexdec( substr( $hex, 0, 2 ) ) / 255;
        $g = hexdec( substr( $hex, 2, 2 ) ) / 255;
        $b = hexdec( substr( $hex, 4, 2 ) ) / 255;

        $r = $r <= 0.03928 ? $r / 12.92 : pow( ( $r + 0.055 ) / 1.055, 2.4 );
        $g = $g <= 0.03928 ? $g / 12.92 : pow( ( $g + 0.055 ) / 1.055, 2.4 );
        $b = $b <= 0.03928 ? $b / 12.92 : pow( ( $b + 0.055 ) / 1.055, 2.4 );

        return 0.2126 * $r + 0.7152 * $g + 0.0722 * $b;
    }

    /**
     * Verifica estructura de encabezados
     */
    private function check_heading_structure( $headings ) {
        $issues = array();

        if ( empty( $headings['h1'] ) ) {
            $issues[] = array(
                'type'    => 'missing_h1',
                'message' => 'La página no tiene encabezado H1',
                'wcag'    => '1.3.1',
                'impact'  => 'serious',
            );
        } elseif ( count( $headings['h1'] ) > 1 ) {
            $issues[] = array(
                'type'    => 'multiple_h1',
                'message' => 'La página tiene múltiples H1 (' . count( $headings['h1'] ) . ')',
                'wcag'    => '1.3.1',
                'impact'  => 'moderate',
            );
        }

        return $issues;
    }

    /**
     * Verifica accesibilidad de enlaces
     */
    private function check_links_accessibility( $links ) {
        $issues = array();
        $generic_texts = array( 'click aquí', 'leer más', 'más info', 'aquí', 'click', 'link' );

        foreach ( $links as $link ) {
            $text = strtolower( trim( $link['text'] ?? '' ) );
            if ( empty( $text ) ) {
                $issues[] = array(
                    'type'    => 'empty_link_text',
                    'message' => 'Enlace sin texto descriptivo',
                    'wcag'    => '2.4.4',
                    'impact'  => 'serious',
                );
            } elseif ( in_array( $text, $generic_texts, true ) ) {
                $issues[] = array(
                    'type'    => 'generic_link_text',
                    'message' => "Texto de enlace genérico: \"{$text}\"",
                    'wcag'    => '2.4.4',
                    'impact'  => 'moderate',
                );
            }
        }

        return $issues;
    }

    /**
     * Extrae formularios de elementos
     */
    private function extract_forms_from_elements( $elements ) {
        $forms = array();
        foreach ( $elements as $element ) {
            $type = $element['type'] ?? '';
            if ( in_array( $type, array( 'contact', 'form', 'newsletter' ), true ) ) {
                $forms[] = $element;
            }
            if ( ! empty( $element['children'] ) ) {
                $forms = array_merge( $forms, $this->extract_forms_from_elements( $element['children'] ) );
            }
        }
        return $forms;
    }

    /**
     * Verifica accesibilidad de formularios
     */
    private function check_forms_accessibility( $forms ) {
        $issues = array();
        foreach ( $forms as $form ) {
            $data = $form['data'] ?? array();
            // Verificar que hay labels
            if ( empty( $data['fields'] ) ) {
                continue;
            }
            foreach ( $data['fields'] as $field ) {
                if ( empty( $field['label'] ) ) {
                    $issues[] = array(
                        'type'    => 'missing_label',
                        'message' => 'Campo de formulario sin etiqueta',
                        'wcag'    => '1.3.1',
                        'impact'  => 'critical',
                    );
                }
            }
        }
        return $issues;
    }

    // =========================================================================
    // ESTADÍSTICAS
    // =========================================================================

    /**
     * Obtiene estadísticas de uso de bloques
     *
     * @return WP_REST_Response
     */
    public function get_blocks_usage_stats() {
        // Usar límite seguro para evitar cargas masivas de memoria
        $limit = flavor_safe_posts_limit( -1 );

        $pages = get_posts( array(
            'post_type'      => 'flavor_landing',
            'post_status'    => array( 'publish', 'draft' ),
            'posts_per_page' => $limit,
        ) );

        // Verificar si hay más páginas
        $total_pages = wp_count_posts( 'flavor_landing' );
        $total_count = ( $total_pages->publish ?? 0 ) + ( $total_pages->draft ?? 0 );
        $is_partial  = $total_count > $limit;

        $block_usage = array();
        $total_blocks = 0;

        foreach ( $pages as $page ) {
            $vbp_data = get_post_meta( $page->ID, '_flavor_vbp_data', true );
            $elements = $vbp_data['elements'] ?? array();

            $this->count_blocks_recursive( $elements, $block_usage, $total_blocks );
        }

        // Ordenar por uso
        arsort( $block_usage );

        // Calcular porcentajes
        $stats = array();
        foreach ( $block_usage as $type => $count ) {
            $stats[] = array(
                'type'       => $type,
                'count'      => $count,
                'percentage' => $total_blocks > 0 ? round( ( $count / $total_blocks ) * 100, 1 ) : 0,
            );
        }

        return new WP_REST_Response( array(
            'success'       => true,
            'total_pages'   => count( $pages ),
            'total_blocks'  => $total_blocks,
            'unique_types'  => count( $block_usage ),
            'blocks'        => $stats,
            'top_5'         => array_slice( $stats, 0, 5 ),
            'is_partial'    => $is_partial,
            'pages_in_site' => $total_count,
        ), 200 );
    }

    /**
     * Cuenta bloques recursivamente
     */
    private function count_blocks_recursive( $elements, &$usage, &$total ) {
        foreach ( $elements as $element ) {
            $type = $element['type'] ?? 'unknown';
            if ( ! isset( $usage[ $type ] ) ) {
                $usage[ $type ] = 0;
            }
            $usage[ $type ]++;
            $total++;

            if ( ! empty( $element['children'] ) ) {
                $this->count_blocks_recursive( $element['children'], $usage, $total );
            }
        }
    }

    /**
     * Obtiene estadísticas generales de VBP
     *
     * @return WP_REST_Response
     */
    public function get_vbp_overview_stats() {
        global $wpdb;

        // Contar páginas
        $pages_count = wp_count_posts( 'flavor_landing' );

        // Páginas por estado
        $pages_by_status = array(
            'publish' => (int) ( $pages_count->publish ?? 0 ),
            'draft'   => (int) ( $pages_count->draft ?? 0 ),
            'trash'   => (int) ( $pages_count->trash ?? 0 ),
        );

        // Páginas por preset
        $pages = get_posts( array(
            'post_type'      => 'flavor_landing',
            'post_status'    => 'any',
            'posts_per_page' => flavor_safe_posts_limit( -1 ),
        ) );

        $presets_usage = array();
        $total_elements = 0;
        $pages_with_seo = 0;

        foreach ( $pages as $page ) {
            $vbp_data = get_post_meta( $page->ID, '_flavor_vbp_data', true );
            $preset = $vbp_data['settings']['design_preset'] ?? 'custom';
            $elements = $vbp_data['elements'] ?? array();

            if ( ! isset( $presets_usage[ $preset ] ) ) {
                $presets_usage[ $preset ] = 0;
            }
            $presets_usage[ $preset ]++;

            $total_elements += $this->count_elements_recursive( $elements );

            // SEO check
            $meta_desc = get_post_meta( $page->ID, '_yoast_wpseo_metadesc', true )
                ?: get_post_meta( $page->ID, '_flavor_seo_description', true );
            if ( ! empty( $meta_desc ) ) {
                $pages_with_seo++;
            }
        }

        arsort( $presets_usage );

        // Calcular promedio de elementos por página
        $total_pages = count( $pages );
        $avg_elements = $total_pages > 0 ? round( $total_elements / $total_pages, 1 ) : 0;

        return new WP_REST_Response( array(
            'success' => true,
            'stats'   => array(
                'total_pages'      => $total_pages,
                'pages_by_status'  => $pages_by_status,
                'total_elements'   => $total_elements,
                'avg_elements'     => $avg_elements,
                'presets_usage'    => $presets_usage,
                'top_preset'       => key( $presets_usage ) ?: 'none',
                'seo_coverage'     => array(
                    'with_meta'    => $pages_with_seo,
                    'without_meta' => $total_pages - $pages_with_seo,
                    'percentage'   => $total_pages > 0 ? round( ( $pages_with_seo / $total_pages ) * 100, 1 ) : 0,
                ),
            ),
            'generated_at' => current_time( 'c' ),
        ), 200 );
    }

    /**
     * Cuenta elementos recursivamente
     */
    private function count_elements_recursive( $elements ) {
        $count = count( $elements );
        foreach ( $elements as $element ) {
            if ( ! empty( $element['children'] ) ) {
                $count += $this->count_elements_recursive( $element['children'] );
            }
        }
        return $count;
    }

    // =========================================================================
    // A/B TESTING Y VARIANTES
    // =========================================================================

    /**
     * Crea una variante de página para A/B testing
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function create_page_variant( $request ) {
        $page_id = (int) $request->get_param( 'id' );
        $variant_type = sanitize_key( $request->get_param( 'variant_type' ) );
        $variant_name = sanitize_text_field( $request->get_param( 'variant_name' ) );

        $post = get_post( $page_id );
        if ( ! $this->is_valid_vbp_post( $post ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Página VBP no encontrada',
            ), 404 );
        }

        $vbp_data = get_post_meta( $page_id, '_flavor_vbp_data', true );
        $elements = $vbp_data['elements'] ?? array();
        $settings = $vbp_data['settings'] ?? array();

        // Determinar nombre de variante
        $existing_variants = get_post_meta( $page_id, '_flavor_ab_variants', true ) ?: array();
        $variant_letter = chr( 66 + count( $existing_variants ) ); // B, C, D...
        $variant_name = $variant_name ?: "Variante {$variant_letter}";

        // Aplicar variaciones según tipo
        switch ( $variant_type ) {
            case 'hero':
                $elements = $this->create_hero_variant( $elements );
                break;

            case 'cta':
                $elements = $this->create_cta_variant( $elements );
                break;

            case 'colors':
                $settings = $this->create_colors_variant( $settings );
                break;

            case 'layout':
                $elements = $this->create_layout_variant( $elements );
                break;

            case 'copy':
            default:
                // Copia exacta, no modificar
                break;
        }

        // Regenerar IDs
        $elements = $this->regenerate_element_ids( $elements );

        // Crear nueva página
        $variant_title = $post->post_title . ' - ' . $variant_name;
        $variant_id = wp_insert_post( array(
            'post_title'  => $variant_title,
            'post_type'   => 'flavor_landing',
            'post_status' => 'draft',
        ) );

        if ( is_wp_error( $variant_id ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => $variant_id->get_error_message(),
            ), 500 );
        }

        // Guardar datos VBP
        $new_vbp_data = array(
            'version'  => '2.0.15',
            'elements' => $elements,
            'settings' => $settings,
        );

        update_post_meta( $variant_id, '_flavor_vbp_data', $new_vbp_data );
        update_post_meta( $variant_id, '_flavor_vbp_version', '2.0.15' );
        update_post_meta( $variant_id, '_flavor_ab_original', $page_id );
        update_post_meta( $variant_id, '_flavor_ab_variant_type', $variant_type );
        update_post_meta( $variant_id, '_flavor_ab_variant_name', $variant_name );

        // Registrar en página original
        $existing_variants[] = array(
            'id'   => $variant_id,
            'name' => $variant_name,
            'type' => $variant_type,
            'created_at' => current_time( 'c' ),
        );
        update_post_meta( $page_id, '_flavor_ab_variants', $existing_variants );

        return new WP_REST_Response( array(
            'success'      => true,
            'variant_id'   => $variant_id,
            'variant_name' => $variant_name,
            'variant_type' => $variant_type,
            'original_id'  => $page_id,
            'edit_url'     => admin_url( "admin.php?page=vbp-editor&post_id={$variant_id}" ),
            'view_url'     => get_permalink( $variant_id ),
        ), 201 );
    }

    /**
     * Crea variante de hero
     */
    private function create_hero_variant( $elements ) {
        foreach ( $elements as &$element ) {
            if ( $element['type'] === 'hero' ) {
                $data = &$element['data'];
                // Intercambiar orden de botones
                if ( ! empty( $data['boton_texto'] ) && ! empty( $data['boton_2_texto'] ) ) {
                    $temp = $data['boton_texto'];
                    $data['boton_texto'] = $data['boton_2_texto'];
                    $data['boton_2_texto'] = $temp;

                    $temp_url = $data['boton_url'] ?? '';
                    $data['boton_url'] = $data['boton_2_url'] ?? '';
                    $data['boton_2_url'] = $temp_url;
                }
                break;
            }
        }
        return $elements;
    }

    /**
     * Crea variante de CTAs
     */
    private function create_cta_variant( $elements ) {
        $cta_texts = array(
            'Empezar ahora', 'Comenzar gratis', 'Prueba gratuita',
            'Únete ya', 'Descubre más', 'Solicitar demo',
        );

        foreach ( $elements as &$element ) {
            if ( ! empty( $element['data']['boton_texto'] ) ) {
                $current = $element['data']['boton_texto'];
                // Seleccionar texto diferente
                $alternatives = array_filter( $cta_texts, function( $t ) use ( $current ) {
                    return strtolower( $t ) !== strtolower( $current );
                } );
                if ( ! empty( $alternatives ) ) {
                    $element['data']['boton_texto'] = $alternatives[ array_rand( $alternatives ) ];
                }
            }

            if ( ! empty( $element['children'] ) ) {
                $element['children'] = $this->create_cta_variant( $element['children'] );
            }
        }

        return $elements;
    }

    /**
     * Crea variante de colores
     */
    private function create_colors_variant( $settings ) {
        $color_schemes = array(
            array( 'primary' => '#2563eb', 'secondary' => '#7c3aed' ),
            array( 'primary' => '#059669', 'secondary' => '#0d9488' ),
            array( 'primary' => '#dc2626', 'secondary' => '#ea580c' ),
            array( 'primary' => '#7c3aed', 'secondary' => '#db2777' ),
        );

        $scheme = $color_schemes[ array_rand( $color_schemes ) ];

        if ( ! empty( $settings['colors'] ) ) {
            $settings['colors']['primary'] = $scheme['primary'];
            $settings['colors']['secondary'] = $scheme['secondary'];
        } else {
            $settings['colors'] = $scheme;
        }

        return $settings;
    }

    /**
     * Crea variante de layout
     */
    private function create_layout_variant( $elements ) {
        // Intercambiar orden de secciones (excepto hero)
        $hero = null;
        $rest = array();

        foreach ( $elements as $element ) {
            if ( $element['type'] === 'hero' ) {
                $hero = $element;
            } else {
                $rest[] = $element;
            }
        }

        // Invertir orden de secciones
        $rest = array_reverse( $rest );

        // Reconstruir con hero al inicio
        $new_elements = array();
        if ( $hero ) {
            $new_elements[] = $hero;
        }
        $new_elements = array_merge( $new_elements, $rest );

        return $new_elements;
    }

    /**
     * Obtiene variantes de una página
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function get_page_variants( $request ) {
        $page_id = (int) $request->get_param( 'id' );
        $post = get_post( $page_id );

        if ( ! $this->is_valid_vbp_post( $post ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Página VBP no encontrada',
            ), 404 );
        }

        $variants = get_post_meta( $page_id, '_flavor_ab_variants', true ) ?: array();

        // Enriquecer datos de variantes
        $enriched_variants = array();
        foreach ( $variants as $variant ) {
            $variant_post = get_post( $variant['id'] );
            if ( $variant_post ) {
                $enriched_variants[] = array_merge( $variant, array(
                    'title'    => $variant_post->post_title,
                    'status'   => $variant_post->post_status,
                    'edit_url' => admin_url( "admin.php?page=vbp-editor&post_id={$variant['id']}" ),
                    'view_url' => get_permalink( $variant['id'] ),
                ) );
            }
        }

        return new WP_REST_Response( array(
            'success'        => true,
            'original_id'    => $page_id,
            'original_title' => $post->post_title,
            'variants_count' => count( $enriched_variants ),
            'variants'       => $enriched_variants,
        ), 200 );
    }

    /**
     * Compara rendimiento de variantes (placeholder)
     *
     * @param WP_REST_Request $request Petición REST.
