    // =============================================
    // MÉTODOS DE BÚSQUEDA, HISTORIAL Y SITEMAP
    // =============================================

    /**
     * Busca en páginas VBP por texto, título o contenido de bloques
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function search_vbp_pages( $request ) {
        global $wpdb;

        $search_query = sanitize_text_field( $request->get_param( 'q' ) );
        $search_type = $request->get_param( 'type' );
        $post_status = $request->get_param( 'status' );
        $per_page = (int) $request->get_param( 'per_page' );
        $page = (int) $request->get_param( 'page' );
        $offset = ( $page - 1 ) * $per_page;

        if ( strlen( $search_query ) < 2 ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'El término de búsqueda debe tener al menos 2 caracteres.',
            ), 400 );
        }

        $search_like = '%' . $wpdb->esc_like( $search_query ) . '%';

        // Construir query base
        $sql_where = array();
        $sql_params = array();

        // Filtrar por tipo de búsqueda
        if ( $search_type === 'title' || $search_type === 'all' ) {
            $sql_where[] = 'p.post_title LIKE %s';
            $sql_params[] = $search_like;
        }

        if ( $search_type === 'content' || $search_type === 'all' ) {
            $sql_where[] = 'p.post_content LIKE %s';
            $sql_params[] = $search_like;
        }

        // Para bloques, buscar en meta
        $search_in_blocks = ( $search_type === 'blocks' || $search_type === 'all' );

        // Filtrar por estado
        $status_clause = '';
        if ( $post_status !== 'any' ) {
            $status_clause = $wpdb->prepare( ' AND p.post_status = %s', $post_status );
        } else {
            $status_clause = " AND p.post_status IN ('publish', 'draft', 'private')";
        }

        $where_clause = implode( ' OR ', $sql_where );

        // Query principal
        $sql = $wpdb->prepare(
            "SELECT SQL_CALC_FOUND_ROWS DISTINCT p.ID, p.post_title, p.post_status, p.post_date, p.post_modified
             FROM {$wpdb->posts} p
             WHERE p.post_type = 'flavor_landing'
             {$status_clause}
             AND ({$where_clause})
             ORDER BY p.post_modified DESC
             LIMIT %d OFFSET %d",
            array_merge( $sql_params, array( $per_page, $offset ) )
        );

        $pages = $wpdb->get_results( $sql );
        $total_results = (int) $wpdb->get_var( 'SELECT FOUND_ROWS()' );

        // Si se busca en bloques, filtrar adicionalmente
        if ( $search_in_blocks && $search_type !== 'all' ) {
            $pages_with_blocks = array();
            $meta_sql = $wpdb->prepare(
                "SELECT p.ID, p.post_title, p.post_status, p.post_date, p.post_modified
                 FROM {$wpdb->posts} p
                 INNER JOIN {$wpdb->postmeta} pm ON p.ID = pm.post_id
                 WHERE p.post_type = 'flavor_landing'
                 {$status_clause}
                 AND pm.meta_key = '_flavor_vbp_elements'
                 AND pm.meta_value LIKE %s
                 ORDER BY p.post_modified DESC
                 LIMIT %d OFFSET %d",
                $search_like,
                $per_page,
                $offset
            );
            $pages = $wpdb->get_results( $meta_sql );
            $total_results = count( $pages );
        }

        // Enriquecer resultados
        $results = array();
        foreach ( $pages as $page_data ) {
            $page_id = $page_data->ID;
            $elements = get_post_meta( $page_id, '_flavor_vbp_elements', true );
            $block_count = is_array( $elements ) ? $this->count_total_blocks( $elements ) : 0;

            // Encontrar coincidencias en bloques
            $block_matches = array();
            if ( is_array( $elements ) && $search_in_blocks ) {
                $block_matches = $this->find_text_in_blocks( $elements, $search_query );
            }

            $results[] = array(
                'id'            => $page_id,
                'title'         => $page_data->post_title,
                'status'        => $page_data->post_status,
                'url'           => get_permalink( $page_id ),
                'edit_url'      => admin_url( "post.php?post={$page_id}&action=edit" ),
                'date_created'  => $page_data->post_date,
                'date_modified' => $page_data->post_modified,
                'block_count'   => $block_count,
                'matches'       => array(
                    'title'   => stripos( $page_data->post_title, $search_query ) !== false,
                    'blocks'  => $block_matches,
                ),
            );
        }

        return new WP_REST_Response( array(
            'success'     => true,
            'query'       => $search_query,
            'type'        => $search_type,
            'total'       => $total_results,
            'page'        => $page,
            'per_page'    => $per_page,
            'total_pages' => ceil( $total_results / $per_page ),
            'results'     => $results,
        ), 200 );
    }

    /**
     * Busca texto en bloques VBP recursivamente
     *
     * @param array  $elements Array de elementos VBP.
     * @param string $search_query Texto a buscar.
     * @return array
     */
    private function find_text_in_blocks( $elements, $search_query ) {
        $matches = array();
        $search_lower = strtolower( $search_query );

        foreach ( $elements as $element ) {
            $block_type = $element['type'] ?? 'unknown';
            $props = $element['props'] ?? array();

            // Buscar en propiedades de texto comunes
            $text_props = array( 'text', 'content', 'title', 'subtitle', 'description', 'label', 'placeholder' );
            foreach ( $text_props as $prop ) {
                if ( isset( $props[ $prop ] ) && is_string( $props[ $prop ] ) ) {
                    if ( stripos( $props[ $prop ], $search_query ) !== false ) {
                        $matches[] = array(
                            'block_type' => $block_type,
                            'property'   => $prop,
                            'snippet'    => $this->get_text_snippet( $props[ $prop ], $search_query, 50 ),
                        );
                    }
                }
            }

            // Buscar en children
            if ( isset( $element['children'] ) && is_array( $element['children'] ) ) {
                $child_matches = $this->find_text_in_blocks( $element['children'], $search_query );
                $matches = array_merge( $matches, $child_matches );
            }
        }

        return $matches;
    }

    /**
     * Obtiene un snippet de texto con el término de búsqueda destacado
     *
     * @param string $text Texto completo.
     * @param string $query Término buscado.
     * @param int    $context_chars Caracteres de contexto.
     * @return string
     */
    private function get_text_snippet( $text, $query, $context_chars = 50 ) {
        $position = stripos( $text, $query );
        if ( $position === false ) {
            return substr( $text, 0, $context_chars * 2 ) . '...';
        }

        $start = max( 0, $position - $context_chars );
        $length = strlen( $query ) + ( $context_chars * 2 );
        $snippet = substr( $text, $start, $length );

        if ( $start > 0 ) {
            $snippet = '...' . $snippet;
        }
        if ( $start + $length < strlen( $text ) ) {
            $snippet .= '...';
        }

        return $snippet;
    }

    /**
     * Obtiene el historial de versiones de una página VBP
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function get_page_history( $request ) {
        $page_id = (int) $request->get_param( 'id' );
        $per_page = (int) $request->get_param( 'per_page' );

        $post = get_post( $page_id );
        if ( ! $this->is_valid_vbp_post( $post ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Página VBP no encontrada.',
            ), 404 );
        }

        // Obtener revisiones
        $revisions = wp_get_post_revisions( $page_id, array(
            'posts_per_page' => $per_page,
            'orderby'        => 'date',
            'order'          => 'DESC',
        ) );

        $history = array();
        foreach ( $revisions as $revision ) {
            $revision_elements = get_post_meta( $revision->ID, '_flavor_vbp_elements', true );
            $block_count = is_array( $revision_elements ) ? $this->count_total_blocks( $revision_elements ) : 0;

            $author = get_user_by( 'id', $revision->post_author );

            $history[] = array(
                'revision_id'   => $revision->ID,
                'date'          => $revision->post_date,
                'date_gmt'      => $revision->post_date_gmt,
                'author'        => array(
                    'id'   => $revision->post_author,
                    'name' => $author ? $author->display_name : 'Desconocido',
                ),
                'title'         => $revision->post_title,
                'block_count'   => $block_count,
                'is_autosave'   => wp_is_post_autosave( $revision->ID ),
                'diff_url'      => admin_url( "revision.php?revision={$revision->ID}" ),
            );
        }

        // Estado actual
        $current_elements = get_post_meta( $page_id, '_flavor_vbp_elements', true );
        $current_author = get_user_by( 'id', $post->post_author );

        return new WP_REST_Response( array(
            'success'  => true,
            'page_id'  => $page_id,
            'current'  => array(
                'title'        => $post->post_title,
                'status'       => $post->post_status,
                'date'         => $post->post_modified,
                'author'       => array(
                    'id'   => $post->post_author,
                    'name' => $current_author ? $current_author->display_name : 'Desconocido',
                ),
                'block_count'  => is_array( $current_elements ) ? $this->count_total_blocks( $current_elements ) : 0,
            ),
            'revisions_count' => count( $revisions ),
            'revisions'       => $history,
        ), 200 );
    }

    /**
     * Restaura una versión específica de una página VBP
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function restore_page_version( $request ) {
        $page_id = (int) $request->get_param( 'id' );
        $revision_id = (int) $request->get_param( 'revision_id' );

        $post = get_post( $page_id );
        if ( ! $this->is_valid_vbp_post( $post ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Página VBP no encontrada.',
            ), 404 );
        }

        $revision = get_post( $revision_id );
        if ( ! $revision || $revision->post_parent !== $page_id ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Revisión no encontrada o no pertenece a esta página.',
            ), 404 );
        }

        // Guardar estado actual antes de restaurar (por si acaso)
        $current_elements = get_post_meta( $page_id, '_flavor_vbp_elements', true );
        update_post_meta( $page_id, '_flavor_vbp_elements_backup', $current_elements );
        update_post_meta( $page_id, '_flavor_vbp_backup_date', current_time( 'mysql' ) );

        // Restaurar contenido de la revisión
        $restored = wp_restore_post_revision( $revision_id );

        if ( ! $restored ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'No se pudo restaurar la revisión.',
            ), 500 );
        }

        // Restaurar meta de elementos VBP si existe
        $revision_elements = get_post_meta( $revision_id, '_flavor_vbp_elements', true );
        if ( ! empty( $revision_elements ) ) {
            update_post_meta( $page_id, '_flavor_vbp_elements', $revision_elements );
        }

        // Limpiar caché
        clean_post_cache( $page_id );

        return new WP_REST_Response( array(
            'success'         => true,
            'message'         => 'Página restaurada correctamente.',
            'page_id'         => $page_id,
            'restored_from'   => $revision_id,
            'restored_date'   => $revision->post_date,
            'backup_created'  => true,
            'current_url'     => get_permalink( $page_id ),
        ), 200 );
    }

    /**
     * Genera un sitemap de páginas VBP
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response|WP_Error
     */
    public function get_vbp_sitemap( $request ) {
        $format = $request->get_param( 'format' );
        $include_drafts = (bool) $request->get_param( 'include_drafts' );

        $post_statuses = array( 'publish' );
        if ( $include_drafts ) {
            $post_statuses[] = 'draft';
        }

        $pages = get_posts( array(
            'post_type'      => 'flavor_landing',
            'post_status'    => $post_statuses,
            'posts_per_page' => flavor_safe_posts_limit( -1 ),
            'orderby'        => 'menu_order title',
            'order'          => 'ASC',
        ) );

        $sitemap_entries = array();
        foreach ( $pages as $page ) {
            $elements = get_post_meta( $page->ID, '_flavor_vbp_elements', true );
            $block_count = is_array( $elements ) ? $this->count_total_blocks( $elements ) : 0;

            $entry = array(
                'id'            => $page->ID,
                'title'         => $page->post_title,
                'slug'          => $page->post_name,
                'url'           => get_permalink( $page->ID ),
                'status'        => $page->post_status,
                'parent'        => $page->post_parent,
                'menu_order'    => $page->menu_order,
                'date_modified' => $page->post_modified,
                'block_count'   => $block_count,
            );

            // Obtener metadatos SEO si existen
            $seo_title = get_post_meta( $page->ID, '_yoast_wpseo_title', true ) ?: get_post_meta( $page->ID, '_flavor_seo_title', true );
            $seo_desc = get_post_meta( $page->ID, '_yoast_wpseo_metadesc', true ) ?: get_post_meta( $page->ID, '_flavor_seo_description', true );

            if ( $seo_title ) {
                $entry['seo_title'] = $seo_title;
            }
            if ( $seo_desc ) {
                $entry['seo_description'] = $seo_desc;
            }

            // Verificar si es homepage
            if ( (int) get_option( 'page_on_front' ) === $page->ID ) {
                $entry['is_homepage'] = true;
            }

            $sitemap_entries[] = $entry;
        }

        // Construir estructura jerárquica
        $hierarchical = $this->build_page_hierarchy( $sitemap_entries );

        // Responder según formato
        if ( $format === 'xml' ) {
            return $this->generate_xml_sitemap( $sitemap_entries );
        } elseif ( $format === 'html' ) {
            return $this->generate_html_sitemap( $hierarchical );
        }

        // Formato JSON (default)
        return new WP_REST_Response( array(
            'success'      => true,
            'total_pages'  => count( $sitemap_entries ),
            'site_url'     => home_url(),
            'generated_at' => current_time( 'c' ),
            'pages'        => $sitemap_entries,
            'hierarchy'    => $hierarchical,
        ), 200 );
    }

    /**
     * Construye una jerarquía de páginas
     *
     * @param array $pages Lista plana de páginas.
     * @return array
     */
    private function build_page_hierarchy( $pages ) {
        $hierarchy = array();
        $pages_by_id = array();

        // Indexar por ID
        foreach ( $pages as $page ) {
            $pages_by_id[ $page['id'] ] = $page;
            $pages_by_id[ $page['id'] ]['children'] = array();
        }

        // Construir jerarquía
        foreach ( $pages_by_id as $id => $page ) {
            if ( $page['parent'] > 0 && isset( $pages_by_id[ $page['parent'] ] ) ) {
                $pages_by_id[ $page['parent'] ]['children'][] = &$pages_by_id[ $id ];
            } else {
                $hierarchy[] = &$pages_by_id[ $id ];
            }
        }

        return $hierarchy;
    }

    /**
     * Genera sitemap en formato XML
     *
     * @param array $pages Lista de páginas.
     * @return WP_REST_Response
     */
    private function generate_xml_sitemap( $pages ) {
        $xml = '<?xml version="1.0" encoding="UTF-8"?>' . "\n";
        $xml .= '<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">' . "\n";

        foreach ( $pages as $page ) {
            if ( $page['status'] !== 'publish' ) {
                continue;
            }

            $xml .= "  <url>\n";
            $xml .= "    <loc>" . esc_url( $page['url'] ) . "</loc>\n";
            $xml .= "    <lastmod>" . date( 'c', strtotime( $page['date_modified'] ) ) . "</lastmod>\n";
            $xml .= "    <changefreq>weekly</changefreq>\n";

            // Prioridad basada en jerarquía
            $priority = $page['parent'] > 0 ? '0.6' : '0.8';
            if ( isset( $page['is_homepage'] ) && $page['is_homepage'] ) {
                $priority = '1.0';
            }
            $xml .= "    <priority>{$priority}</priority>\n";
            $xml .= "  </url>\n";
        }

        $xml .= '</urlset>';

        return new WP_REST_Response( array(
            'success'      => true,
            'format'       => 'xml',
            'content_type' => 'application/xml',
            'xml'          => $xml,
        ), 200, array(
            'Content-Type' => 'application/xml; charset=utf-8',
        ) );
    }

    /**
     * Genera sitemap en formato HTML
     *
     * @param array $hierarchy Jerarquía de páginas.
     * @return WP_REST_Response
     */
    private function generate_html_sitemap( $hierarchy ) {
        $html = '<nav class="vbp-sitemap" role="navigation" aria-label="Sitemap">' . "\n";
        $html .= $this->render_sitemap_list( $hierarchy );
        $html .= '</nav>';

        return new WP_REST_Response( array(
            'success'      => true,
            'format'       => 'html',
            'content_type' => 'text/html',
            'html'         => $html,
        ), 200 );
    }

    /**
     * Renderiza lista de sitemap recursivamente
     *
     * @param array $pages Lista de páginas.
     * @param int   $level Nivel de anidación.
     * @return string
     */
    private function render_sitemap_list( $pages, $level = 0 ) {
        if ( empty( $pages ) ) {
            return '';
        }

        $indent = str_repeat( '  ', $level );
        $html = "{$indent}<ul class=\"sitemap-level-{$level}\">\n";

        foreach ( $pages as $page ) {
            $classes = array( 'sitemap-item' );
            if ( isset( $page['is_homepage'] ) && $page['is_homepage'] ) {
                $classes[] = 'is-homepage';
            }
            if ( $page['status'] !== 'publish' ) {
                $classes[] = 'is-draft';
            }

            $class_attr = implode( ' ', $classes );
            $html .= "{$indent}  <li class=\"{$class_attr}\">\n";
            $html .= "{$indent}    <a href=\"" . esc_url( $page['url'] ) . "\">" . esc_html( $page['title'] ) . "</a>\n";

            if ( ! empty( $page['children'] ) ) {
                $html .= $this->render_sitemap_list( $page['children'], $level + 1 );
            }

            $html .= "{$indent}  </li>\n";
        }

        $html .= "{$indent}</ul>\n";

        return $html;
    }

    // =============================================
    // MÉTODOS DE UTILIDADES AVANZADAS
    // =============================================

    /**
     * Valida la estructura de bloques de una página VBP
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function validate_page_blocks( $request ) {
        $page_id = (int) $request->get_param( 'id' );

        $post = get_post( $page_id );
        if ( ! $this->is_valid_vbp_post( $post ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Página VBP no encontrada.',
            ), 404 );
        }

        $elements = get_post_meta( $page_id, '_flavor_vbp_elements', true );
        if ( empty( $elements ) || ! is_array( $elements ) ) {
            return new WP_REST_Response( array(
                'success'  => true,
                'valid'    => true,
                'page_id'  => $page_id,
                'message'  => 'La página no tiene bloques VBP.',
                'warnings' => array(),
                'errors'   => array(),
            ), 200 );
        }

        $validation = $this->validate_blocks_structure( $elements );

        return new WP_REST_Response( array(
            'success'      => true,
            'valid'        => $validation['valid'],
            'page_id'      => $page_id,
            'total_blocks' => $validation['total_blocks'],
            'warnings'     => $validation['warnings'],
            'errors'       => $validation['errors'],
            'summary'      => array(
                'blocks_by_type' => $validation['blocks_by_type'],
                'max_depth'      => $validation['max_depth'],
                'empty_blocks'   => $validation['empty_blocks'],
            ),
        ), 200 );
    }

    /**
     * Valida bloques sin guardar (preview)
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function validate_blocks_preview( $request ) {
        $blocks = $request->get_param( 'blocks' );

        if ( ! is_array( $blocks ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'El parámetro blocks debe ser un array.',
            ), 400 );
        }

        $validation = $this->validate_blocks_structure( $blocks );

        return new WP_REST_Response( array(
            'success'      => true,
            'valid'        => $validation['valid'],
            'total_blocks' => $validation['total_blocks'],
            'warnings'     => $validation['warnings'],
            'errors'       => $validation['errors'],
            'summary'      => array(
                'blocks_by_type' => $validation['blocks_by_type'],
                'max_depth'      => $validation['max_depth'],
                'empty_blocks'   => $validation['empty_blocks'],
            ),
        ), 200 );
    }

    /**
     * Valida la estructura de bloques recursivamente
     *
     * @param array $blocks Array de bloques.
     * @param int   $depth Profundidad actual.
     * @param string $path Ruta del bloque actual.
     * @return array
     */
    private function validate_blocks_structure( $blocks, $depth = 0, $path = '' ) {
        $result = array(
            'valid'          => true,
            'total_blocks'   => 0,
            'warnings'       => array(),
            'errors'         => array(),
            'blocks_by_type' => array(),
            'max_depth'      => $depth,
            'empty_blocks'   => 0,
        );

        $valid_block_types = array(
            'section', 'container', 'row', 'column', 'columns',
            'heading', 'text', 'paragraph', 'button', 'image',
            'video', 'icon', 'spacer', 'divider', 'list',
            'card', 'feature-card', 'testimonial', 'pricing-table',
            'faq', 'accordion', 'tabs', 'gallery', 'slider',
            'form', 'contact-form', 'newsletter', 'social-links',
            'map', 'embed', 'html', 'shortcode', 'module-shortcode',
            'hero', 'cta', 'features', 'team', 'stats', 'timeline',
        );

        foreach ( $blocks as $index => $block ) {
            $block_path = $path ? "{$path}[{$index}]" : "[{$index}]";
            $result['total_blocks']++;

            // Verificar tipo
            $block_type = $block['type'] ?? null;
            if ( empty( $block_type ) ) {
                $result['errors'][] = array(
                    'path'    => $block_path,
                    'message' => 'Bloque sin tipo definido.',
                    'code'    => 'missing_type',
                );
                $result['valid'] = false;
                continue;
            }

            // Contar por tipo
            if ( ! isset( $result['blocks_by_type'][ $block_type ] ) ) {
                $result['blocks_by_type'][ $block_type ] = 0;
            }
            $result['blocks_by_type'][ $block_type ]++;

            // Advertir sobre tipos desconocidos
            if ( ! in_array( $block_type, $valid_block_types, true ) ) {
                $result['warnings'][] = array(
                    'path'    => $block_path,
                    'message' => "Tipo de bloque desconocido: {$block_type}",
                    'code'    => 'unknown_type',
                );
            }

            // Verificar props
            $props = $block['props'] ?? array();
            if ( empty( $props ) && ! in_array( $block_type, array( 'spacer', 'divider' ), true ) ) {
                $result['warnings'][] = array(
                    'path'    => $block_path,
                    'type'    => $block_type,
                    'message' => 'Bloque sin propiedades.',
                    'code'    => 'empty_props',
                );
                $result['empty_blocks']++;
            }

            // Verificar contenido en bloques de texto
            $text_blocks = array( 'heading', 'text', 'paragraph', 'button' );
            if ( in_array( $block_type, $text_blocks, true ) ) {
                $text_content = $props['text'] ?? $props['content'] ?? '';
                if ( empty( trim( $text_content ) ) ) {
                    $result['warnings'][] = array(
                        'path'    => $block_path,
                        'type'    => $block_type,
                        'message' => 'Bloque de texto sin contenido.',
                        'code'    => 'empty_text',
                    );
                    $result['empty_blocks']++;
                }
            }

            // Verificar imagen
            if ( $block_type === 'image' ) {
                $src = $props['src'] ?? $props['url'] ?? '';
                if ( empty( $src ) ) {
                    $result['warnings'][] = array(
                        'path'    => $block_path,
                        'message' => 'Bloque de imagen sin URL.',
                        'code'    => 'missing_image_src',
                    );
                }
                $alt = $props['alt'] ?? '';
                if ( empty( $alt ) ) {
                    $result['warnings'][] = array(
                        'path'    => $block_path,
                        'message' => 'Imagen sin texto alternativo (accesibilidad).',
                        'code'    => 'missing_alt',
                    );
                }
            }

            // Verificar botón
            if ( $block_type === 'button' ) {
                $url = $props['url'] ?? $props['href'] ?? '';
                if ( empty( $url ) || $url === '#' ) {
                    $result['warnings'][] = array(
                        'path'    => $block_path,
                        'message' => 'Botón sin URL de destino.',
                        'code'    => 'missing_button_url',
                    );
                }
            }

            // Validar children recursivamente
            if ( isset( $block['children'] ) && is_array( $block['children'] ) ) {
                $child_result = $this->validate_blocks_structure( $block['children'], $depth + 1, $block_path );

                $result['total_blocks'] += $child_result['total_blocks'];
                $result['warnings'] = array_merge( $result['warnings'], $child_result['warnings'] );
                $result['errors'] = array_merge( $result['errors'], $child_result['errors'] );
                $result['empty_blocks'] += $child_result['empty_blocks'];

                foreach ( $child_result['blocks_by_type'] as $type => $count ) {
                    if ( ! isset( $result['blocks_by_type'][ $type ] ) ) {
                        $result['blocks_by_type'][ $type ] = 0;
                    }
                    $result['blocks_by_type'][ $type ] += $count;
                }

                if ( $child_result['max_depth'] > $result['max_depth'] ) {
                    $result['max_depth'] = $child_result['max_depth'];
                }

                if ( ! $child_result['valid'] ) {
                    $result['valid'] = false;
                }
            }
        }

        // Advertencia de profundidad excesiva
        if ( $result['max_depth'] > 10 ) {
            $result['warnings'][] = array(
                'path'    => 'root',
                'message' => "Anidación muy profunda ({$result['max_depth']} niveles). Considerar simplificar.",
                'code'    => 'deep_nesting',
            );
        }

        return $result;
    }

    /**
     * Exporta una página VBP a HTML estático
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function export_page_html( $request ) {
        $page_id = (int) $request->get_param( 'id' );
        $include_styles = (bool) $request->get_param( 'include_styles' );
        $include_scripts = (bool) $request->get_param( 'include_scripts' );
        $minify = (bool) $request->get_param( 'minify' );

        $post = get_post( $page_id );
        if ( ! $this->is_valid_vbp_post( $post ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Página VBP no encontrada.',
            ), 404 );
        }

        $elements = get_post_meta( $page_id, '_flavor_vbp_elements', true );
        $styles = get_post_meta( $page_id, '_flavor_vbp_styles', true );

        // Generar HTML del contenido
        $content_html = $this->render_elements_to_html( $elements ?: array() );

        // Construir documento HTML completo
        $html = '<!DOCTYPE html>' . "\n";
        $html .= '<html lang="es">' . "\n";
        $html .= '<head>' . "\n";
        $html .= '  <meta charset="UTF-8">' . "\n";
        $html .= '  <meta name="viewport" content="width=device-width, initial-scale=1.0">' . "\n";
        $html .= '  <title>' . esc_html( $post->post_title ) . '</title>' . "\n";

        // Meta SEO
        $seo_desc = get_post_meta( $page_id, '_flavor_seo_description', true );
        if ( $seo_desc ) {
            $html .= '  <meta name="description" content="' . esc_attr( $seo_desc ) . '">' . "\n";
        }

        // Estilos
        if ( $include_styles ) {
            $html .= '  <style>' . "\n";
            $html .= $this->get_vbp_base_styles();
            if ( ! empty( $styles ) ) {
                $html .= $this->convert_styles_to_css( $styles );
            }
            $html .= '  </style>' . "\n";
        }

        $html .= '</head>' . "\n";
        $html .= '<body class="vbp-page vbp-exported">' . "\n";
        $html .= $content_html;

        if ( $include_scripts ) {
            $html .= '  <script>' . "\n";
            $html .= $this->get_vbp_base_scripts();
            $html .= '  </script>' . "\n";
        }

        $html .= '</body>' . "\n";
        $html .= '</html>';

        // Minificar si se solicita
        if ( $minify ) {
            $html = $this->minify_html( $html );
        }

        return new WP_REST_Response( array(
            'success'   => true,
            'page_id'   => $page_id,
            'title'     => $post->post_title,
            'html'      => $html,
            'size'      => strlen( $html ),
            'size_kb'   => round( strlen( $html ) / 1024, 2 ),
            'minified'  => $minify,
            'options'   => array(
                'styles'  => $include_styles,
                'scripts' => $include_scripts,
            ),
        ), 200 );
    }

    /**
     * Renderiza elementos VBP a HTML
     *
     * @param array $elements Array de elementos.
     * @param int   $indent Nivel de indentación.
     * @return string
     */
    private function render_elements_to_html( $elements, $indent = 0 ) {
        $html = '';
        $indent_str = str_repeat( '  ', $indent );

        foreach ( $elements as $element ) {
            $type = $element['type'] ?? 'div';
            $props = $element['props'] ?? array();
            $children = $element['children'] ?? array();

            // Mapear tipos VBP a tags HTML
            $tag_map = array(
                'section'   => 'section',
                'container' => 'div',
                'row'       => 'div',
                'column'    => 'div',
                'columns'   => 'div',
                'heading'   => 'h2',
                'text'      => 'p',
                'paragraph' => 'p',
                'button'    => 'a',
                'image'     => 'img',
                'spacer'    => 'div',
                'divider'   => 'hr',
                'list'      => 'ul',
            );

            $tag = $tag_map[ $type ] ?? 'div';

            // Construir clases
            $classes = array( "vbp-{$type}" );
            if ( ! empty( $props['className'] ) ) {
                $classes[] = $props['className'];
            }

            // Construir atributos
            $attrs = array(
                'class' => implode( ' ', $classes ),
            );

            // Atributos específicos por tipo
            if ( $type === 'heading' && isset( $props['level'] ) ) {
                $tag = 'h' . min( 6, max( 1, (int) $props['level'] ) );
            }

            if ( $type === 'button' ) {
                $attrs['href'] = $props['url'] ?? $props['href'] ?? '#';
                if ( ! empty( $props['target'] ) ) {
                    $attrs['target'] = $props['target'];
                }
            }

            if ( $type === 'image' ) {
                $attrs['src'] = $props['src'] ?? $props['url'] ?? '';
                $attrs['alt'] = $props['alt'] ?? '';
                if ( ! empty( $props['width'] ) ) {
                    $attrs['width'] = $props['width'];
                }
                if ( ! empty( $props['height'] ) ) {
                    $attrs['height'] = $props['height'];
                }
            }

            // Estilos inline
            $inline_styles = array();
            if ( ! empty( $props['color'] ) ) {
                $inline_styles[] = "color: {$props['color']}";
            }
            if ( ! empty( $props['backgroundColor'] ) ) {
                $inline_styles[] = "background-color: {$props['backgroundColor']}";
            }
            if ( ! empty( $props['padding'] ) ) {
                $inline_styles[] = "padding: {$props['padding']}";
            }
            if ( ! empty( $props['margin'] ) ) {
                $inline_styles[] = "margin: {$props['margin']}";
            }
            if ( ! empty( $props['textAlign'] ) || ! empty( $props['align'] ) ) {
                $align = $props['textAlign'] ?? $props['align'];
                $inline_styles[] = "text-align: {$align}";
            }

            if ( ! empty( $inline_styles ) ) {
                $attrs['style'] = implode( '; ', $inline_styles );
            }

            // Construir string de atributos
            $attr_str = '';
            foreach ( $attrs as $attr_name => $attr_value ) {
                $attr_str .= ' ' . $attr_name . '="' . esc_attr( $attr_value ) . '"';
            }

            // Tags auto-cerrados
            $self_closing = array( 'img', 'hr', 'br', 'input' );
            if ( in_array( $tag, $self_closing, true ) ) {
                $html .= "{$indent_str}<{$tag}{$attr_str} />\n";
            } else {
                $html .= "{$indent_str}<{$tag}{$attr_str}>";

                // Contenido de texto
                $text_content = $props['text'] ?? $props['content'] ?? '';
                if ( ! empty( $text_content ) ) {
                    $html .= esc_html( $text_content );
                }

                // Children
                if ( ! empty( $children ) ) {
                    $html .= "\n";
                    $html .= $this->render_elements_to_html( $children, $indent + 1 );
                    $html .= $indent_str;
                }

                $html .= "</{$tag}>\n";
            }
        }

        return $html;
    }

    /**
     * Obtiene estilos base de VBP
     *
     * @return string
     */
    private function get_vbp_base_styles() {
        return '
    * { box-sizing: border-box; }
    body { margin: 0; font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; line-height: 1.6; }
    .vbp-section { padding: 4rem 2rem; }
    .vbp-container { max-width: 1200px; margin: 0 auto; }
    .vbp-row { display: flex; flex-wrap: wrap; gap: 1rem; }
    .vbp-column { flex: 1; min-width: 250px; }
    .vbp-columns { display: grid; gap: 2rem; }
    .vbp-heading { margin: 0 0 1rem; }
    .vbp-text, .vbp-paragraph { margin: 0 0 1rem; }
    .vbp-button { display: inline-block; padding: 0.75rem 1.5rem; background: #3b82f6; color: white; text-decoration: none; border-radius: 0.375rem; transition: background 0.2s; }
    .vbp-button:hover { background: #2563eb; }
    .vbp-image { max-width: 100%; height: auto; }
    .vbp-spacer { height: 2rem; }
    .vbp-divider { border: none; border-top: 1px solid #e5e7eb; margin: 2rem 0; }
    @media (max-width: 768px) {
      .vbp-section { padding: 2rem 1rem; }
      .vbp-columns { grid-template-columns: 1fr !important; }
    }
    ';
    }

    /**
     * Obtiene scripts base de VBP
     *
     * @return string
     */
    private function get_vbp_base_scripts() {
        return '
    document.addEventListener("DOMContentLoaded", function() {
      // Smooth scroll para anclas
      document.querySelectorAll("a[href^=\'#\']").forEach(function(anchor) {
        anchor.addEventListener("click", function(e) {
          var target = document.querySelector(this.getAttribute("href"));
          if (target) {
            e.preventDefault();
            target.scrollIntoView({ behavior: "smooth" });
          }
        });
      });
    });
    ';
    }

    /**
     * Convierte estilos VBP a CSS
     *
     * @param array $styles Estilos VBP.
     * @return string
     */
    private function convert_styles_to_css( $styles ) {
        $css = '';

        if ( isset( $styles['colors'] ) ) {
            $css .= ':root {';
            foreach ( $styles['colors'] as $name => $value ) {
                $css .= " --vbp-{$name}: {$value};";
            }
            $css .= ' }';
        }

        if ( isset( $styles['advanced']['customCss'] ) ) {
            $css .= $styles['advanced']['customCss'];
        }

        return $css;
    }

    /**
     * Minifica HTML
     *
     * @param string $html HTML a minificar.
     * @return string
     */
    private function minify_html( $html ) {
        // Eliminar comentarios HTML
        $html = preg_replace( '/<!--(?!<!)[^\[>].*?-->/s', '', $html );

        // Eliminar espacios en blanco excesivos
        $html = preg_replace( '/\s+/', ' ', $html );

        // Eliminar espacios alrededor de tags
        $html = preg_replace( '/>\s+</', '><', $html );

        // Eliminar espacios al inicio y final
        $html = trim( $html );

        return $html;
    }

    /**
     * Compara dos páginas VBP
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function compare_pages( $request ) {
        $page_a_id = (int) $request->get_param( 'page_a' );
        $page_b_id = (int) $request->get_param( 'page_b' );
        $detail_level = $request->get_param( 'detail_level' );

        $post_a = get_post( $page_a_id );
        $post_b = get_post( $page_b_id );

        if ( ! $post_a || $post_a->post_type !== 'flavor_landing' ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => "Página A (ID: {$page_a_id}) no encontrada.",
            ), 404 );
        }

        if ( ! $post_b || $post_b->post_type !== 'flavor_landing' ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => "Página B (ID: {$page_b_id}) no encontrada.",
            ), 404 );
        }

        $elements_a = get_post_meta( $page_a_id, '_flavor_vbp_elements', true ) ?: array();
        $elements_b = get_post_meta( $page_b_id, '_flavor_vbp_elements', true ) ?: array();

        $blocks_count_a = $this->count_total_blocks( $elements_a );
        $blocks_count_b = $this->count_total_blocks( $elements_b );

        $comparison = array(
            'page_a' => array(
                'id'           => $page_a_id,
                'title'        => $post_a->post_title,
                'status'       => $post_a->post_status,
                'block_count'  => $blocks_count_a,
                'modified'     => $post_a->post_modified,
            ),
            'page_b' => array(
                'id'           => $page_b_id,
                'title'        => $post_b->post_title,
                'status'       => $post_b->post_status,
                'block_count'  => $blocks_count_b,
                'modified'     => $post_b->post_modified,
            ),
            'differences' => array(
                'title_same'       => $post_a->post_title === $post_b->post_title,
                'status_same'      => $post_a->post_status === $post_b->post_status,
                'block_count_diff' => $blocks_count_a - $blocks_count_b,
            ),
        );

        // Comparación de bloques por tipo
        if ( $detail_level === 'blocks' || $detail_level === 'full' ) {
            $types_a = $this->get_block_types_count( $elements_a );
            $types_b = $this->get_block_types_count( $elements_b );

            $all_types = array_unique( array_merge( array_keys( $types_a ), array_keys( $types_b ) ) );
            $type_comparison = array();

            foreach ( $all_types as $type ) {
                $count_a = $types_a[ $type ] ?? 0;
                $count_b = $types_b[ $type ] ?? 0;
                $type_comparison[ $type ] = array(
                    'page_a' => $count_a,
                    'page_b' => $count_b,
                    'diff'   => $count_a - $count_b,
                );
            }

            $comparison['blocks_by_type'] = $type_comparison;
        }

        // Comparación detallada de contenido
        if ( $detail_level === 'full' ) {
            $content_diff = $this->compare_block_content( $elements_a, $elements_b );
            $comparison['content_diff'] = $content_diff;
        }

        return new WP_REST_Response( array(
            'success'      => true,
            'detail_level' => $detail_level,
            'comparison'   => $comparison,
        ), 200 );
    }

    /**
     * Obtiene conteo de bloques por tipo
     *
     * @param array $elements Elementos VBP.
     * @return array
     */
    private function get_block_types_count( $elements ) {
        $counts = array();

        foreach ( $elements as $element ) {
            $type = $element['type'] ?? 'unknown';
            if ( ! isset( $counts[ $type ] ) ) {
                $counts[ $type ] = 0;
            }
            $counts[ $type ]++;

            if ( isset( $element['children'] ) && is_array( $element['children'] ) ) {
                $child_counts = $this->get_block_types_count( $element['children'] );
                foreach ( $child_counts as $child_type => $child_count ) {
                    if ( ! isset( $counts[ $child_type ] ) ) {
                        $counts[ $child_type ] = 0;
                    }
                    $counts[ $child_type ] += $child_count;
                }
            }
        }

        return $counts;
    }

    /**
     * Compara contenido de bloques entre dos páginas
     *
     * @param array $elements_a Elementos de página A.
     * @param array $elements_b Elementos de página B.
     * @return array
     */
    private function compare_block_content( $elements_a, $elements_b ) {
        $texts_a = $this->extract_all_texts( $elements_a );
        $texts_b = $this->extract_all_texts( $elements_b );

        $only_in_a = array_diff( $texts_a, $texts_b );
        $only_in_b = array_diff( $texts_b, $texts_a );
        $common = array_intersect( $texts_a, $texts_b );

        return array(
            'texts_in_a'     => count( $texts_a ),
            'texts_in_b'     => count( $texts_b ),
            'common_texts'   => count( $common ),
            'only_in_a'      => array_values( $only_in_a ),
            'only_in_b'      => array_values( $only_in_b ),
            'similarity'     => count( $texts_a ) > 0 || count( $texts_b ) > 0
                ? round( ( count( $common ) * 2 ) / ( count( $texts_a ) + count( $texts_b ) ) * 100, 2 )
                : 100,
        );
    }

    /**
     * Extrae todos los textos de los bloques
     *
     * @param array $elements Elementos VBP.
     * @return array
     */
    private function extract_all_texts( $elements ) {
        $texts = array();

        foreach ( $elements as $element ) {
            $props = $element['props'] ?? array();

            foreach ( array( 'text', 'content', 'title', 'subtitle', 'description' ) as $prop ) {
                if ( ! empty( $props[ $prop ] ) && is_string( $props[ $prop ] ) ) {
                    $texts[] = trim( $props[ $prop ] );
                }
            }

            if ( isset( $element['children'] ) && is_array( $element['children'] ) ) {
                $texts = array_merge( $texts, $this->extract_all_texts( $element['children'] ) );
            }
        }

        return array_filter( $texts );
    }

    /**
     * Obtiene bloques huérfanos o con problemas
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function get_orphan_blocks( $request ) {
        global $wpdb;

        $issues = array();

        // Buscar páginas con elementos VBP vacíos o corruptos
        $pages_with_vbp = $wpdb->get_results(
            "SELECT p.ID, p.post_title, pm.meta_value
             FROM {$wpdb->posts} p
             INNER JOIN {$wpdb->postmeta} pm ON p.ID = pm.post_id
             WHERE p.post_type = 'flavor_landing'
             AND p.post_status IN ('publish', 'draft', 'private')
             AND pm.meta_key = '_flavor_vbp_elements'"
        );

        foreach ( $pages_with_vbp as $page ) {
            $elements = maybe_unserialize( $page->meta_value );

            if ( $elements === false ) {
                $issues[] = array(
                    'page_id'  => $page->ID,
                    'title'    => $page->post_title,
                    'issue'    => 'corrupt_data',
                    'message'  => 'Datos de elementos VBP corruptos (no se puede deserializar).',
                    'severity' => 'error',
                );
                continue;
            }

            if ( empty( $elements ) ) {
                $issues[] = array(
                    'page_id'  => $page->ID,
                    'title'    => $page->post_title,
                    'issue'    => 'empty_elements',
                    'message'  => 'Página sin elementos VBP.',
                    'severity' => 'warning',
                );
                continue;
            }

            // Validar estructura
            $validation = $this->validate_blocks_structure( $elements );
            if ( ! empty( $validation['errors'] ) ) {
                $issues[] = array(
                    'page_id'      => $page->ID,
                    'title'        => $page->post_title,
                    'issue'        => 'validation_errors',
                    'message'      => 'Página con errores de validación.',
                    'severity'     => 'error',
                    'error_count'  => count( $validation['errors'] ),
                    'errors'       => array_slice( $validation['errors'], 0, 5 ),
                );
            } elseif ( count( $validation['warnings'] ) > 5 ) {
                $issues[] = array(
                    'page_id'       => $page->ID,
                    'title'         => $page->post_title,
                    'issue'         => 'many_warnings',
                    'message'       => 'Página con muchas advertencias.',
                    'severity'      => 'warning',
                    'warning_count' => count( $validation['warnings'] ),
                );
            }
        }

        return new WP_REST_Response( array(
            'success'      => true,
            'total_pages'  => count( $pages_with_vbp ),
            'issues_found' => count( $issues ),
            'issues'       => $issues,
            'summary'      => array(
                'errors'   => count( array_filter( $issues, function( $i ) { return $i['severity'] === 'error'; } ) ),
                'warnings' => count( array_filter( $issues, function( $i ) { return $i['severity'] === 'warning'; } ) ),
            ),
        ), 200 );
    }

    /**
     * Limpia caché de VBP
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function clear_vbp_cache( $request ) {
        $page_id = $request->get_param( 'page_id' );
        $cleared = array();

        if ( $page_id ) {
            // Limpiar caché de página específica
            clean_post_cache( $page_id );
            delete_transient( "vbp_rendered_{$page_id}" );
            delete_transient( "vbp_styles_{$page_id}" );
            $cleared[] = "page_{$page_id}";
        } else {
            // Limpiar todo el caché VBP
            global $wpdb;

            // Eliminar transients de VBP
            $wpdb->query(
                "DELETE FROM {$wpdb->options}
                 WHERE option_name LIKE '_transient_vbp_%'
                 OR option_name LIKE '_transient_timeout_vbp_%'"
            );

            // Limpiar caché de objeto si está disponible
            if ( function_exists( 'wp_cache_flush_group' ) ) {
                wp_cache_flush_group( 'vbp' );
            }

            $cleared[] = 'all_vbp_transients';
            $cleared[] = 'object_cache';
        }

        // Limpiar caché de plugins populares
        if ( function_exists( 'wp_cache_clear_cache' ) ) {
            wp_cache_clear_cache();
            $cleared[] = 'wp_super_cache';
        }

        if ( function_exists( 'w3tc_flush_all' ) ) {
            w3tc_flush_all();
            $cleared[] = 'w3_total_cache';
        }

        if ( class_exists( 'LiteSpeed_Cache_API' ) ) {
            LiteSpeed_Cache_API::purge_all();
            $cleared[] = 'litespeed';
        }

        return new WP_REST_Response( array(
            'success'     => true,
            'message'     => 'Caché limpiada correctamente.',
            'page_id'     => $page_id ?: 'all',
            'cleared'     => $cleared,
            'timestamp'   => current_time( 'c' ),
        ), 200 );
    }

    // =============================================
    // MÉTODOS DE MANIPULACIÓN DE BLOQUES
    // =============================================

    /**
     * Copia bloques entre páginas
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function copy_blocks_between_pages( $request ) {
        $source_page_id = (int) $request->get_param( 'source_page_id' );
        $target_page_id = (int) $request->get_param( 'target_page_id' );
        $block_indices = $request->get_param( 'block_indices' );
        $position = $request->get_param( 'position' );
        $insert_at = $request->get_param( 'insert_at' );

        // Verificar páginas
        $source_post = get_post( $source_page_id );
        $target_post = get_post( $target_page_id );

        if ( ! $source_post || $source_post->post_type !== 'flavor_landing' ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Página origen no encontrada.',
            ), 404 );
        }

        if ( ! $target_post || $target_post->post_type !== 'flavor_landing' ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Página destino no encontrada.',
            ), 404 );
        }

        // Obtener elementos
        $source_elements = get_post_meta( $source_page_id, '_flavor_vbp_elements', true ) ?: array();
        $target_elements = get_post_meta( $target_page_id, '_flavor_vbp_elements', true ) ?: array();

        if ( empty( $source_elements ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'La página origen no tiene bloques.',
            ), 400 );
        }

        // Validar índices
        $max_index = count( $source_elements ) - 1;
        foreach ( $block_indices as $index ) {
            if ( $index < 0 || $index > $max_index ) {
                return new WP_REST_Response( array(
                    'success' => false,
                    'error'   => "Índice {$index} fuera de rango (0-{$max_index}).",
                ), 400 );
            }
        }

        // Extraer bloques a copiar
        $blocks_to_copy = array();
        foreach ( $block_indices as $index ) {
            $block = $source_elements[ $index ];
            // Regenerar IDs para evitar conflictos
            $blocks_to_copy[] = $this->regenerate_element_ids( array( $block ) )[0];
        }

        // Insertar en posición correcta
        switch ( $position ) {
            case 'start':
                $target_elements = array_merge( $blocks_to_copy, $target_elements );
                break;
            case 'index':
                $insert_at = max( 0, min( $insert_at, count( $target_elements ) ) );
                array_splice( $target_elements, $insert_at, 0, $blocks_to_copy );
                break;
            case 'end':
            default:
                $target_elements = array_merge( $target_elements, $blocks_to_copy );
                break;
        }

        // Guardar
        update_post_meta( $target_page_id, '_flavor_vbp_elements', $target_elements );

        return new WP_REST_Response( array(
            'success'       => true,
            'message'       => 'Bloques copiados correctamente.',
            'blocks_copied' => count( $blocks_to_copy ),
            'source_page'   => $source_page_id,
            'target_page'   => $target_page_id,
            'new_total'     => count( $target_elements ),
        ), 200 );
    }

    /**
     * Reordena bloques en una página
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function reorder_page_blocks( $request ) {
        $page_id = (int) $request->get_param( 'id' );
        $new_order = $request->get_param( 'order' );

        $post = get_post( $page_id );
        if ( ! $this->is_valid_vbp_post( $post ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Página no encontrada.',
            ), 404 );
        }

        $elements = get_post_meta( $page_id, '_flavor_vbp_elements', true ) ?: array();

        if ( empty( $elements ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'La página no tiene bloques.',
            ), 400 );
        }

        // Validar que el nuevo orden tenga los mismos índices
        $expected_indices = range( 0, count( $elements ) - 1 );
        $provided_indices = array_map( 'intval', $new_order );
        sort( $provided_indices );

        if ( $provided_indices !== $expected_indices ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'El nuevo orden debe contener todos los índices existentes (0-' . ( count( $elements ) - 1 ) . ').',
            ), 400 );
        }

        // Reordenar
        $reordered_elements = array();
        foreach ( $new_order as $index ) {
            $reordered_elements[] = $elements[ $index ];
        }

        // Guardar
        update_post_meta( $page_id, '_flavor_vbp_elements', $reordered_elements );

        return new WP_REST_Response( array(
            'success'     => true,
            'message'     => 'Bloques reordenados correctamente.',
            'page_id'     => $page_id,
            'new_order'   => $new_order,
            'total_blocks'=> count( $reordered_elements ),
        ), 200 );
    }

    /**
     * Mueve un bloque dentro de una página
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function move_block( $request ) {
        $page_id = (int) $request->get_param( 'id' );
        $from_index = (int) $request->get_param( 'from_index' );
        $to_index = (int) $request->get_param( 'to_index' );

        $post = get_post( $page_id );
        if ( ! $this->is_valid_vbp_post( $post ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Página no encontrada.',
            ), 404 );
        }

        $elements = get_post_meta( $page_id, '_flavor_vbp_elements', true ) ?: array();
        $max_index = count( $elements ) - 1;

        if ( $from_index < 0 || $from_index > $max_index ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => "Índice origen {$from_index} fuera de rango (0-{$max_index}).",
            ), 400 );
        }

        if ( $to_index < 0 || $to_index > $max_index ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => "Índice destino {$to_index} fuera de rango (0-{$max_index}).",
            ), 400 );
        }

        // Extraer bloque
        $block = $elements[ $from_index ];
        array_splice( $elements, $from_index, 1 );

        // Insertar en nueva posición
        array_splice( $elements, $to_index, 0, array( $block ) );

        // Guardar
        update_post_meta( $page_id, '_flavor_vbp_elements', $elements );

        return new WP_REST_Response( array(
            'success'    => true,
            'message'    => 'Bloque movido correctamente.',
            'page_id'    => $page_id,
            'from_index' => $from_index,
            'to_index'   => $to_index,
            'block_type' => $block['type'] ?? 'unknown',
        ), 200 );
    }

    /**
     * Elimina un bloque específico
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function delete_block( $request ) {
        $page_id = (int) $request->get_param( 'id' );
        $block_index = (int) $request->get_param( 'block_index' );

        $post = get_post( $page_id );
        if ( ! $this->is_valid_vbp_post( $post ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Página no encontrada.',
            ), 404 );
        }

        $elements = get_post_meta( $page_id, '_flavor_vbp_elements', true ) ?: array();
        $max_index = count( $elements ) - 1;

        if ( $block_index < 0 || $block_index > $max_index ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => "Índice {$block_index} fuera de rango (0-{$max_index}).",
            ), 400 );
        }

        // Guardar info del bloque eliminado
        $deleted_block = $elements[ $block_index ];

        // Eliminar
        array_splice( $elements, $block_index, 1 );

        // Guardar
        update_post_meta( $page_id, '_flavor_vbp_elements', $elements );

        return new WP_REST_Response( array(
            'success'       => true,
            'message'       => 'Bloque eliminado correctamente.',
            'page_id'       => $page_id,
            'deleted_index' => $block_index,
            'deleted_type'  => $deleted_block['type'] ?? 'unknown',
            'remaining'     => count( $elements ),
        ), 200 );
    }

    /**
     * Obtiene el CSS generado de una página
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function get_page_css( $request ) {
        $page_id = (int) $request->get_param( 'id' );
        $minify = (bool) $request->get_param( 'minify' );
        $include_base = (bool) $request->get_param( 'include_base' );

        $post = get_post( $page_id );
        if ( ! $this->is_valid_vbp_post( $post ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Página no encontrada.',
            ), 404 );
        }

        $css = '';

        // Estilos base
        if ( $include_base ) {
            $css .= $this->get_vbp_base_styles();
        }

        // Estilos de la página
        $styles = get_post_meta( $page_id, '_flavor_vbp_styles', true );
        if ( ! empty( $styles ) ) {
            $css .= "\n/* Page Styles */\n";
            $css .= $this->convert_styles_to_css( $styles );
        }

        // Estilos de elementos
        $elements = get_post_meta( $page_id, '_flavor_vbp_elements', true );
        if ( ! empty( $elements ) ) {
            $element_css = $this->generate_elements_css( $elements );
            if ( $element_css ) {
                $css .= "\n/* Element Styles */\n";
                $css .= $element_css;
            }
        }

        // Minificar si se solicita
        if ( $minify ) {
            $css = $this->minify_css( $css );
        }

        return new WP_REST_Response( array(
            'success'      => true,
            'page_id'      => $page_id,
            'css'          => $css,
            'size'         => strlen( $css ),
            'size_kb'      => round( strlen( $css ) / 1024, 2 ),
            'minified'     => $minify,
            'include_base' => $include_base,
        ), 200 );
    }

    /**
     * Genera CSS de elementos recursivamente
     *
     * @param array  $elements Elementos VBP.
     * @param string $parent_selector Selector padre.
     * @return string
     */
    private function generate_elements_css( $elements, $parent_selector = '' ) {
        $css = '';

        foreach ( $elements as $index => $element ) {
            $element_id = $element['id'] ?? "el_{$index}";
            $type = $element['type'] ?? 'div';
            $props = $element['props'] ?? array();
            $selector = $parent_selector ? "{$parent_selector} .{$element_id}" : ".{$element_id}";

            $styles = array();

            // Convertir props a CSS
            if ( ! empty( $props['backgroundColor'] ) ) {
                $styles[] = "background-color: {$props['backgroundColor']}";
            }
            if ( ! empty( $props['color'] ) ) {
                $styles[] = "color: {$props['color']}";
            }
            if ( ! empty( $props['padding'] ) ) {
                $styles[] = "padding: {$props['padding']}";
            }
            if ( ! empty( $props['margin'] ) ) {
                $styles[] = "margin: {$props['margin']}";
            }
            if ( ! empty( $props['fontSize'] ) ) {
                $styles[] = "font-size: {$props['fontSize']}";
            }
            if ( ! empty( $props['fontWeight'] ) ) {
                $styles[] = "font-weight: {$props['fontWeight']}";
            }
            if ( ! empty( $props['textAlign'] ) || ! empty( $props['align'] ) ) {
                $align = $props['textAlign'] ?? $props['align'];
                $styles[] = "text-align: {$align}";
            }
            if ( ! empty( $props['borderRadius'] ) ) {
                $styles[] = "border-radius: {$props['borderRadius']}";
            }
            if ( ! empty( $props['boxShadow'] ) ) {
                $styles[] = "box-shadow: {$props['boxShadow']}";
            }

            if ( ! empty( $styles ) ) {
                $css .= "{$selector} { " . implode( '; ', $styles ) . "; }\n";
            }

            // Procesar children
            if ( ! empty( $element['children'] ) ) {
                $css .= $this->generate_elements_css( $element['children'], $selector );
            }
        }

        return $css;
    }

    /**
     * Minifica CSS
     *
     * @param string $css CSS a minificar.
     * @return string
     */
    private function minify_css( $css ) {
        // Eliminar comentarios
        $css = preg_replace( '!/\*[^*]*\*+([^/][^*]*\*+)*/!', '', $css );

        // Eliminar espacios en blanco
        $css = preg_replace( '/\s+/', ' ', $css );

        // Eliminar espacios alrededor de caracteres
        $css = preg_replace( '/\s*([\{\}\:\;\,])\s*/', '$1', $css );

        // Eliminar punto y coma antes de llave
        $css = str_replace( ';}', '}', $css );

        return trim( $css );
    }

    /**
     * Obtiene estadísticas de rendimiento de una página
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function get_page_performance( $request ) {
        $page_id = (int) $request->get_param( 'id' );

        $post = get_post( $page_id );
        if ( ! $this->is_valid_vbp_post( $post ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Página no encontrada.',
            ), 404 );
        }

        $elements = get_post_meta( $page_id, '_flavor_vbp_elements', true ) ?: array();
        $styles = get_post_meta( $page_id, '_flavor_vbp_styles', true ) ?: array();

        // Calcular métricas
        $block_count = $this->count_total_blocks( $elements );
        $image_count = $this->count_images_in_blocks( $elements );
        $text_length = $this->calculate_text_length( $elements );
        $max_depth = $this->calculate_max_depth( $elements );

        // Generar HTML y CSS para calcular tamaños
        $html = $this->render_elements_to_html( $elements );
        $css = $this->get_vbp_base_styles() . $this->convert_styles_to_css( $styles );

        $html_size = strlen( $html );
        $css_size = strlen( $css );
        $total_size = $html_size + $css_size;

        // Calcular puntuación de rendimiento
        $performance_score = 100;
        $issues = array();

        // Penalizar por muchos bloques
        if ( $block_count > 50 ) {
            $performance_score -= 10;
            $issues[] = array(
                'type'    => 'warning',
                'message' => "Muchos bloques ({$block_count}). Considerar simplificar.",
            );
        }

        // Penalizar por profundidad excesiva
        if ( $max_depth > 8 ) {
            $performance_score -= 15;
            $issues[] = array(
                'type'    => 'warning',
                'message' => "Anidación muy profunda ({$max_depth} niveles).",
            );
        }

        // Penalizar por muchas imágenes sin lazy loading info
        if ( $image_count > 10 ) {
            $performance_score -= 5;
            $issues[] = array(
                'type'    => 'info',
                'message' => "Muchas imágenes ({$image_count}). Verificar lazy loading.",
            );
        }

        // Penalizar por tamaño grande
        if ( $total_size > 100000 ) {
            $performance_score -= 10;
            $issues[] = array(
                'type'    => 'warning',
                'message' => 'Tamaño de página grande (' . round( $total_size / 1024, 1 ) . ' KB).',
            );
        }

        $performance_score = max( 0, $performance_score );

        // Determinar grade
        $grade = 'A';
        if ( $performance_score < 90 ) $grade = 'B';
        if ( $performance_score < 75 ) $grade = 'C';
        if ( $performance_score < 60 ) $grade = 'D';
        if ( $performance_score < 40 ) $grade = 'F';

        return new WP_REST_Response( array(
            'success'     => true,
            'page_id'     => $page_id,
            'score'       => $performance_score,
            'grade'       => $grade,
            'metrics'     => array(
                'block_count'   => $block_count,
                'image_count'   => $image_count,
                'text_length'   => $text_length,
                'max_depth'     => $max_depth,
                'html_size'     => $html_size,
                'html_size_kb'  => round( $html_size / 1024, 2 ),
                'css_size'      => $css_size,
                'css_size_kb'   => round( $css_size / 1024, 2 ),
                'total_size'    => $total_size,
                'total_size_kb' => round( $total_size / 1024, 2 ),
            ),
            'issues'      => $issues,
            'suggestions' => $this->get_performance_suggestions( $block_count, $max_depth, $image_count, $total_size ),
        ), 200 );
    }

    /**
     * Cuenta imágenes en bloques
     *
     * @param array $elements Elementos VBP.
     * @return int
     */
    private function count_images_in_blocks( $elements ) {
        $count = 0;

        foreach ( $elements as $element ) {
            if ( ( $element['type'] ?? '' ) === 'image' ) {
                $count++;
            }

            $props = $element['props'] ?? array();
            if ( ! empty( $props['backgroundImage'] ) || ! empty( $props['src'] ) ) {
                $count++;
            }

            if ( ! empty( $element['children'] ) ) {
                $count += $this->count_images_in_blocks( $element['children'] );
            }
        }

        return $count;
    }

    /**
     * Calcula longitud total de texto
     *
     * @param array $elements Elementos VBP.
     * @return int
     */
    private function calculate_text_length( $elements ) {
        $length = 0;

        foreach ( $elements as $element ) {
            $props = $element['props'] ?? array();

            foreach ( array( 'text', 'content', 'title', 'subtitle', 'description' ) as $prop ) {
                if ( ! empty( $props[ $prop ] ) && is_string( $props[ $prop ] ) ) {
                    $length += strlen( $props[ $prop ] );
                }
            }

            if ( ! empty( $element['children'] ) ) {
                $length += $this->calculate_text_length( $element['children'] );
            }
        }

        return $length;
    }

    /**
     * Calcula profundidad máxima de anidación
     *
     * @param array $elements Elementos VBP.
     * @param int   $current_depth Profundidad actual.
     * @return int
     */
    private function calculate_max_depth( $elements, $current_depth = 1 ) {
        $max = $current_depth;

        foreach ( $elements as $element ) {
            if ( ! empty( $element['children'] ) ) {
                $child_depth = $this->calculate_max_depth( $element['children'], $current_depth + 1 );
                if ( $child_depth > $max ) {
                    $max = $child_depth;
                }
            }
        }

        return $max;
    }

    /**
     * Genera sugerencias de rendimiento
     *
     * @param int $blocks Cantidad de bloques.
     * @param int $depth Profundidad máxima.
     * @param int $images Cantidad de imágenes.
     * @param int $size Tamaño total.
     * @return array
     */
    private function get_performance_suggestions( $blocks, $depth, $images, $size ) {
        $suggestions = array();

        if ( $blocks > 30 ) {
            $suggestions[] = 'Considerar dividir la página en secciones más pequeñas.';
        }

        if ( $depth > 6 ) {
            $suggestions[] = 'Reducir la anidación de bloques para mejorar el rendimiento.';
        }

        if ( $images > 5 ) {
            $suggestions[] = 'Asegurar que las imágenes usan lazy loading y están optimizadas.';
        }

        if ( $size > 50000 ) {
            $suggestions[] = 'Considerar minificar el HTML/CSS para reducir el tamaño.';
        }

        if ( empty( $suggestions ) ) {
            $suggestions[] = '¡Buen trabajo! La página está optimizada.';
        }

        return $suggestions;
    }

    /**
     * Obtiene bloques de una página
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function get_page_blocks( $request ) {
        $page_id = (int) $request->get_param( 'id' );
        $flat = (bool) $request->get_param( 'flat' );

        $post = get_post( $page_id );
        if ( ! $this->is_valid_vbp_post( $post ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Página no encontrada.',
            ), 404 );
        }

        $elements = get_post_meta( $page_id, '_flavor_vbp_elements', true ) ?: array();

        if ( $flat ) {
            $elements = $this->flatten_blocks( $elements );
        }

        // Añadir índices
        $indexed_elements = array();
        foreach ( $elements as $index => $element ) {
            $element['_index'] = $index;
            $element['_type_label'] = $this->get_block_type_label( $element['type'] ?? 'unknown' );
            $indexed_elements[] = $element;
        }

        return new WP_REST_Response( array(
            'success'     => true,
            'page_id'     => $page_id,
            'total'       => count( $indexed_elements ),
            'flat'        => $flat,
            'blocks'      => $indexed_elements,
        ), 200 );
    }

    /**
     * Aplana bloques jerárquicos
     *
     * @param array  $elements Elementos VBP.
     * @param string $path Ruta actual.
     * @return array
     */
    private function flatten_blocks( $elements, $path = '' ) {
        $flat = array();

        foreach ( $elements as $index => $element ) {
            $current_path = $path ? "{$path}.{$index}" : (string) $index;
            $element['_path'] = $current_path;
            $flat[] = $element;

            if ( ! empty( $element['children'] ) ) {
                $children = $element['children'];
                unset( $element['children'] );
                $flat = array_merge( $flat, $this->flatten_blocks( $children, $current_path ) );
            }
        }

        return $flat;
    }

    /**
     * Obtiene etiqueta de tipo de bloque
     *
     * @param string $type Tipo de bloque.
     * @return string
     */
    private function get_block_type_label( $type ) {
        $labels = array(
            'section'     => 'Sección',
            'container'   => 'Contenedor',
            'row'         => 'Fila',
            'column'      => 'Columna',
            'columns'     => 'Columnas',
            'heading'     => 'Encabezado',
            'text'        => 'Texto',
            'paragraph'   => 'Párrafo',
            'button'      => 'Botón',
            'image'       => 'Imagen',
            'video'       => 'Video',
            'spacer'      => 'Espaciador',
            'divider'     => 'Divisor',
            'hero'        => 'Hero',
            'cta'         => 'Llamada a acción',
            'features'    => 'Características',
            'testimonials'=> 'Testimonios',
            'faq'         => 'FAQ',
            'contact'     => 'Contacto',
            'gallery'     => 'Galería',
            'slider'      => 'Slider',
        );

        return $labels[ $type ] ?? ucfirst( $type );
    }

    /**
     * Añade un bloque a una página
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function add_block_to_page( $request ) {
        $page_id = (int) $request->get_param( 'id' );
        $block = $request->get_param( 'block' );
        $position = $request->get_param( 'position' );
        $insert_at = $request->get_param( 'insert_at' );

        $post = get_post( $page_id );
        if ( ! $this->is_valid_vbp_post( $post ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Página no encontrada.',
            ), 404 );
        }

        if ( empty( $block ) || ! is_array( $block ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Bloque inválido.',
            ), 400 );
        }

        // Asegurar que el bloque tiene ID
        if ( empty( $block['id'] ) ) {
            $block['id'] = 'el_' . bin2hex( random_bytes( 6 ) );
        }

        $elements = get_post_meta( $page_id, '_flavor_vbp_elements', true ) ?: array();

        // Insertar en posición correcta
        switch ( $position ) {
            case 'start':
                array_unshift( $elements, $block );
                $inserted_at = 0;
                break;
            case 'index':
                $insert_at = max( 0, min( $insert_at, count( $elements ) ) );
                array_splice( $elements, $insert_at, 0, array( $block ) );
                $inserted_at = $insert_at;
                break;
            case 'end':
            default:
                $elements[] = $block;
                $inserted_at = count( $elements ) - 1;
                break;
        }

        // Guardar
        update_post_meta( $page_id, '_flavor_vbp_elements', $elements );

        return new WP_REST_Response( array(
            'success'     => true,
            'message'     => 'Bloque añadido correctamente.',
            'page_id'     => $page_id,
            'block_id'    => $block['id'],
            'block_type'  => $block['type'] ?? 'unknown',
            'inserted_at' => $inserted_at,
            'total_blocks'=> count( $elements ),
        ), 201 );
    }

