    /**
     * Lista páginas favoritas
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function list_favorite_pages( $request ) {
        $user_id = get_current_user_id();
        $favorites = get_user_meta( $user_id, 'flavor_vbp_favorites', true ) ?: array();

        $pages = array();
        foreach ( $favorites as $page_id ) {
            $post = get_post( $page_id );
            if ( $post && $this->is_supported_post_type( $post->post_type ) ) {
                $pages[] = array(
                    'id'       => $page_id,
                    'title'    => $post->post_title,
                    'status'   => $post->post_status,
                    'url'      => get_permalink( $page_id ),
                    'edit_url' => admin_url( "admin.php?page=vbp-editor&post_id={$page_id}" ),
                    'modified' => $post->post_modified,
                );
            }
        }

        return new WP_REST_Response( array(
            'success' => true,
            'total'   => count( $pages ),
            'pages'   => $pages,
        ), 200 );
    }

    /**
     * Marca/desmarca página como favorita
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function toggle_favorite( $request ) {
        $page_id = (int) $request->get_param( 'id' );
        $user_id = get_current_user_id();

        $post = get_post( $page_id );
        if ( ! $this->is_valid_vbp_post( $post ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Página no encontrada.',
            ), 404 );
        }

        $favorites = get_user_meta( $user_id, 'flavor_vbp_favorites', true ) ?: array();

        $is_favorite = in_array( $page_id, $favorites, true );

        if ( $is_favorite ) {
            $favorites = array_diff( $favorites, array( $page_id ) );
            $action = 'removed';
        } else {
            $favorites[] = $page_id;
            $action = 'added';
        }

        update_user_meta( $user_id, 'flavor_vbp_favorites', array_values( $favorites ) );

        return new WP_REST_Response( array(
            'success'     => true,
            'page_id'     => $page_id,
            'is_favorite' => ! $is_favorite,
            'action'      => $action,
            'message'     => $action === 'added' ? 'Añadido a favoritos' : 'Eliminado de favoritos',
        ), 200 );
    }

    /**
     * Lista etiquetas VBP disponibles
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function list_vbp_tags( $request ) {
        global $wpdb;

        // Obtener todas las etiquetas usadas
        $results = $wpdb->get_col(
            "SELECT DISTINCT meta_value FROM {$wpdb->postmeta}
             WHERE meta_key = '_flavor_vbp_tags'
             AND meta_value != ''"
        );

        $all_tags = array();
        foreach ( $results as $tags_json ) {
            $tags = json_decode( $tags_json, true );
            if ( is_array( $tags ) ) {
                $all_tags = array_merge( $all_tags, $tags );
            }
        }

        $tag_counts = array_count_values( $all_tags );
        arsort( $tag_counts );

        $tags = array();
        foreach ( $tag_counts as $tag => $count ) {
            $tags[] = array(
                'name'  => $tag,
                'count' => $count,
            );
        }

        return new WP_REST_Response( array(
            'success' => true,
            'total'   => count( $tags ),
            'tags'    => $tags,
        ), 200 );
    }

    /**
     * Asigna etiquetas a una página
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function set_page_tags( $request ) {
        $page_id = (int) $request->get_param( 'id' );
        $tags = $request->get_param( 'tags' );

        $post = get_post( $page_id );
        if ( ! $this->is_valid_vbp_post( $post ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Página no encontrada.',
            ), 404 );
        }

        // Sanitizar etiquetas
        $clean_tags = array_map( 'sanitize_text_field', $tags );
        $clean_tags = array_filter( $clean_tags );
        $clean_tags = array_unique( $clean_tags );

        update_post_meta( $page_id, '_flavor_vbp_tags', wp_json_encode( array_values( $clean_tags ) ) );

        return new WP_REST_Response( array(
            'success' => true,
            'page_id' => $page_id,
            'tags'    => array_values( $clean_tags ),
            'count'   => count( $clean_tags ),
        ), 200 );
    }

    /**
     * Obtiene etiquetas de una página
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function get_page_tags( $request ) {
        $page_id = (int) $request->get_param( 'id' );

        $post = get_post( $page_id );
        if ( ! $this->is_valid_vbp_post( $post ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Página no encontrada.',
            ), 404 );
        }

        $tags_json = get_post_meta( $page_id, '_flavor_vbp_tags', true );
        $tags = $tags_json ? json_decode( $tags_json, true ) : array();

        return new WP_REST_Response( array(
            'success' => true,
            'page_id' => $page_id,
            'tags'    => $tags ?: array(),
        ), 200 );
    }

    // =============================================
    // MÉTODOS DE SNAPSHOTS
    // =============================================

    /**
     * Lista snapshots de una página
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function list_page_snapshots( $request ) {
        $page_id = (int) $request->get_param( 'id' );

        $post = get_post( $page_id );
        if ( ! $this->is_valid_vbp_post( $post ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Página no encontrada.',
            ), 404 );
        }

        $snapshots = get_post_meta( $page_id, '_flavor_vbp_snapshots', true ) ?: array();

        // Añadir info adicional
        foreach ( $snapshots as &$snapshot ) {
            $author = get_user_by( 'id', $snapshot['created_by'] ?? 0 );
            $snapshot['author_name'] = $author ? $author->display_name : 'Desconocido';
        }

        return new WP_REST_Response( array(
            'success'   => true,
            'page_id'   => $page_id,
            'total'     => count( $snapshots ),
            'snapshots' => array_values( $snapshots ),
        ), 200 );
    }

    /**
     * Crea snapshot manual
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function create_page_snapshot( $request ) {
        $page_id = (int) $request->get_param( 'id' );
        $name = sanitize_text_field( $request->get_param( 'name' ) );
        $description = sanitize_textarea_field( $request->get_param( 'description' ) );

        $post = get_post( $page_id );
        if ( ! $this->is_valid_vbp_post( $post ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Página no encontrada.',
            ), 404 );
        }

        $elements = get_post_meta( $page_id, '_flavor_vbp_elements', true );
        $styles = get_post_meta( $page_id, '_flavor_vbp_styles', true );

        $snapshot_id = 'snap_' . bin2hex( random_bytes( 6 ) );

        $snapshots = get_post_meta( $page_id, '_flavor_vbp_snapshots', true ) ?: array();

        // Limitar a 20 snapshots por página
        if ( count( $snapshots ) >= 20 ) {
            array_shift( $snapshots );
        }

        $snapshots[ $snapshot_id ] = array(
            'id'          => $snapshot_id,
            'name'        => $name ?: 'Snapshot ' . date( 'Y-m-d H:i' ),
            'description' => $description,
            'elements'    => $elements,
            'styles'      => $styles,
            'title'       => $post->post_title,
            'created_at'  => current_time( 'mysql' ),
            'created_by'  => get_current_user_id(),
            'block_count' => is_array( $elements ) ? $this->count_total_blocks( $elements ) : 0,
        );

        update_post_meta( $page_id, '_flavor_vbp_snapshots', $snapshots );

        return new WP_REST_Response( array(
            'success'     => true,
            'message'     => 'Snapshot creado correctamente.',
            'page_id'     => $page_id,
            'snapshot_id' => $snapshot_id,
            'name'        => $snapshots[ $snapshot_id ]['name'],
        ), 201 );
    }

    /**
     * Restaura un snapshot
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function restore_page_snapshot( $request ) {
        $page_id = (int) $request->get_param( 'id' );
        $snapshot_id = $request->get_param( 'snapshot_id' );

        $post = get_post( $page_id );
        if ( ! $this->is_valid_vbp_post( $post ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Página no encontrada.',
            ), 404 );
        }

        $snapshots = get_post_meta( $page_id, '_flavor_vbp_snapshots', true ) ?: array();

        if ( ! isset( $snapshots[ $snapshot_id ] ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Snapshot no encontrado.',
            ), 404 );
        }

        $snapshot = $snapshots[ $snapshot_id ];

        // Crear snapshot de respaldo antes de restaurar
        $current_elements = get_post_meta( $page_id, '_flavor_vbp_elements', true );
        $current_styles = get_post_meta( $page_id, '_flavor_vbp_styles', true );

        $backup_id = 'backup_' . bin2hex( random_bytes( 4 ) );
        $snapshots[ $backup_id ] = array(
            'id'          => $backup_id,
            'name'        => 'Backup antes de restaurar ' . $snapshot['name'],
            'description' => 'Creado automáticamente',
            'elements'    => $current_elements,
            'styles'      => $current_styles,
            'title'       => $post->post_title,
            'created_at'  => current_time( 'mysql' ),
            'created_by'  => get_current_user_id(),
            'is_backup'   => true,
        );

        update_post_meta( $page_id, '_flavor_vbp_snapshots', $snapshots );

        // Restaurar
        update_post_meta( $page_id, '_flavor_vbp_elements', $snapshot['elements'] );
        if ( ! empty( $snapshot['styles'] ) ) {
            update_post_meta( $page_id, '_flavor_vbp_styles', $snapshot['styles'] );
        }

        return new WP_REST_Response( array(
            'success'        => true,
            'message'        => 'Snapshot restaurado correctamente.',
            'page_id'        => $page_id,
            'restored_from'  => $snapshot_id,
            'snapshot_name'  => $snapshot['name'],
            'backup_created' => $backup_id,
        ), 200 );
    }

    /**
     * Elimina un snapshot
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function delete_page_snapshot( $request ) {
        $page_id = (int) $request->get_param( 'id' );
        $snapshot_id = $request->get_param( 'snapshot_id' );

        $snapshots = get_post_meta( $page_id, '_flavor_vbp_snapshots', true ) ?: array();

        if ( ! isset( $snapshots[ $snapshot_id ] ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Snapshot no encontrado.',
            ), 404 );
        }

        $deleted_name = $snapshots[ $snapshot_id ]['name'];
        unset( $snapshots[ $snapshot_id ] );

        update_post_meta( $page_id, '_flavor_vbp_snapshots', $snapshots );

        return new WP_REST_Response( array(
            'success' => true,
            'message' => "Snapshot '{$deleted_name}' eliminado.",
        ), 200 );
    }

    // =============================================
    // MÉTODOS DE DASHBOARD Y AUDITORÍAS
    // =============================================

    /**
     * Obtiene dashboard de estadísticas VBP
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function get_vbp_dashboard( $request ) {
        global $wpdb;

        // Contar páginas por estado
        $status_counts = $wpdb->get_results(
            "SELECT post_status, COUNT(*) as count
             FROM {$wpdb->posts}
             WHERE post_type = 'flavor_landing'
             GROUP BY post_status",
            OBJECT_K
        );

        $total_pages = 0;
        $pages_by_status = array();
        foreach ( $status_counts as $status => $data ) {
            $pages_by_status[ $status ] = (int) $data->count;
            $total_pages += (int) $data->count;
        }

        // Obtener páginas recientes
        $recent_pages = get_posts( array(
            'post_type'      => 'flavor_landing',
            'posts_per_page' => 5,
            'orderby'        => 'modified',
            'order'          => 'DESC',
        ) );

        $recent = array();
        foreach ( $recent_pages as $page ) {
            $recent[] = array(
                'id'       => $page->ID,
                'title'    => $page->post_title,
                'status'   => $page->post_status,
                'modified' => $page->post_modified,
            );
        }

        // Contar bloques totales
        $total_blocks = 0;
        $block_types = array();
        $pages_meta = $wpdb->get_col(
            "SELECT meta_value FROM {$wpdb->postmeta}
             WHERE meta_key = '_flavor_vbp_elements'"
        );

        foreach ( $pages_meta as $meta ) {
            $elements = maybe_unserialize( $meta );
            if ( is_array( $elements ) ) {
                $count = $this->count_total_blocks( $elements );
                $total_blocks += $count;

                $types = $this->get_block_types_count( $elements );
                foreach ( $types as $type => $type_count ) {
                    if ( ! isset( $block_types[ $type ] ) ) {
                        $block_types[ $type ] = 0;
                    }
                    $block_types[ $type ] += $type_count;
                }
            }
        }

        arsort( $block_types );

        // Plantillas guardadas
        $templates = get_option( 'flavor_vbp_block_templates', array() );

        return new WP_REST_Response( array(
            'success' => true,
            'stats'   => array(
                'total_pages'       => $total_pages,
                'pages_by_status'   => $pages_by_status,
                'total_blocks'      => $total_blocks,
                'avg_blocks_per_page' => $total_pages > 0 ? round( $total_blocks / $total_pages, 1 ) : 0,
                'block_types'       => array_slice( $block_types, 0, 10, true ),
                'templates_saved'   => count( $templates ),
            ),
            'recent_pages' => $recent,
            'system'       => array(
                'vbp_version'   => '1.0.0',
                'php_version'   => PHP_VERSION,
                'wp_version'    => get_bloginfo( 'version' ),
            ),
        ), 200 );
    }

    /**
     * Auditoría de medios usados
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function get_media_audit( $request ) {
        global $wpdb;

        $images = array();
        $pages_meta = $wpdb->get_results(
            "SELECT post_id, meta_value FROM {$wpdb->postmeta}
             WHERE meta_key = '_flavor_vbp_elements'"
        );

        foreach ( $pages_meta as $row ) {
            $elements = maybe_unserialize( $row->meta_value );
            if ( is_array( $elements ) ) {
                $page_images = $this->extract_images_from_blocks( $elements );
                foreach ( $page_images as $image ) {
                    $image['page_id'] = $row->post_id;
                    $images[] = $image;
                }
            }
        }

        // Agrupar por URL
        $unique_images = array();
        foreach ( $images as $img ) {
            $url = $img['url'];
            if ( ! isset( $unique_images[ $url ] ) ) {
                $unique_images[ $url ] = array(
                    'url'        => $url,
                    'has_alt'    => ! empty( $img['alt'] ),
                    'alt'        => $img['alt'] ?? '',
                    'used_in'    => array(),
                );
            }
            $unique_images[ $url ]['used_in'][] = $img['page_id'];
        }

        // Estadísticas
        $total_images = count( $images );
        $unique_count = count( $unique_images );
        $missing_alt = count( array_filter( $unique_images, function( $img ) {
            return ! $img['has_alt'];
        } ) );

        return new WP_REST_Response( array(
            'success' => true,
            'stats'   => array(
                'total_uses'    => $total_images,
                'unique_images' => $unique_count,
                'missing_alt'   => $missing_alt,
            ),
            'images'  => array_values( $unique_images ),
        ), 200 );
    }

    /**
     * Extrae imágenes de bloques
     *
     * @param array $elements Elementos VBP.
     * @return array
     */
    private function extract_images_from_blocks( $elements ) {
        $images = array();

        foreach ( $elements as $element ) {
            $type = $element['type'] ?? '';
            $props = $element['props'] ?? array();

            if ( $type === 'image' ) {
                $images[] = array(
                    'url'  => $props['src'] ?? $props['url'] ?? '',
                    'alt'  => $props['alt'] ?? '',
                    'type' => 'image_block',
                );
            }

            if ( ! empty( $props['backgroundImage'] ) ) {
                $images[] = array(
                    'url'  => $props['backgroundImage'],
                    'alt'  => '',
                    'type' => 'background',
                );
            }

            if ( ! empty( $element['children'] ) ) {
                $images = array_merge( $images, $this->extract_images_from_blocks( $element['children'] ) );
            }
        }

        return array_filter( $images, function( $img ) {
            return ! empty( $img['url'] );
        } );
    }

    /**
     * Auditoría de shortcodes usados
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function get_shortcodes_audit( $request ) {
        global $wpdb;

        $shortcodes = array();
        $pages_meta = $wpdb->get_results(
            "SELECT post_id, meta_value FROM {$wpdb->postmeta}
             WHERE meta_key = '_flavor_vbp_elements'"
        );

        foreach ( $pages_meta as $row ) {
            $elements = maybe_unserialize( $row->meta_value );
            if ( is_array( $elements ) ) {
                $page_shortcodes = $this->extract_shortcodes_from_blocks( $elements );
                foreach ( $page_shortcodes as $sc ) {
                    $sc['page_id'] = $row->post_id;
                    $shortcodes[] = $sc;
                }
            }
        }

        // Agrupar por nombre de shortcode
        $grouped = array();
        foreach ( $shortcodes as $sc ) {
            $name = $sc['shortcode'];
            if ( ! isset( $grouped[ $name ] ) ) {
                $grouped[ $name ] = array(
                    'shortcode' => $name,
                    'count'     => 0,
                    'pages'     => array(),
                );
            }
            $grouped[ $name ]['count']++;
            if ( ! in_array( $sc['page_id'], $grouped[ $name ]['pages'], true ) ) {
                $grouped[ $name ]['pages'][] = $sc['page_id'];
            }
        }

        usort( $grouped, function( $a, $b ) {
            return $b['count'] - $a['count'];
        } );

        return new WP_REST_Response( array(
            'success'    => true,
            'total_uses' => count( $shortcodes ),
            'unique'     => count( $grouped ),
            'shortcodes' => array_values( $grouped ),
        ), 200 );
    }

    /**
     * Extrae shortcodes de bloques
     *
     * @param array $elements Elementos VBP.
     * @return array
     */
    private function extract_shortcodes_from_blocks( $elements ) {
        $shortcodes = array();

        foreach ( $elements as $element ) {
            $type = $element['type'] ?? '';
            $props = $element['props'] ?? array();

            // Bloque de shortcode
            if ( $type === 'shortcode' || $type === 'module-shortcode' ) {
                $shortcodes[] = array(
                    'shortcode' => $props['shortcode'] ?? $props['module'] ?? 'unknown',
                    'type'      => $type,
                );
            }

            // Buscar shortcodes en texto
            foreach ( array( 'content', 'text', 'html' ) as $prop ) {
                if ( ! empty( $props[ $prop ] ) && is_string( $props[ $prop ] ) ) {
                    preg_match_all( '/\[([a-zA-Z_][a-zA-Z0-9_-]*)/', $props[ $prop ], $matches );
                    if ( ! empty( $matches[1] ) ) {
                        foreach ( $matches[1] as $sc_name ) {
                            $shortcodes[] = array(
                                'shortcode' => $sc_name,
                                'type'      => 'embedded',
                            );
                        }
                    }
                }
            }

            if ( ! empty( $element['children'] ) ) {
                $shortcodes = array_merge( $shortcodes, $this->extract_shortcodes_from_blocks( $element['children'] ) );
            }
        }

        return $shortcodes;
    }

