    /**
     * Actualiza el design system completo.
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function update_design_system( $request ) {
        $current = get_option( 'flavor_vbp_design_system', array() );

        $sections = array( 'colors', 'typography', 'spacing', 'borders', 'shadows' );

        foreach ( $sections as $section ) {
            $value = $request->get_param( $section );
            if ( is_array( $value ) ) {
                $current[ $section ] = array_merge( $current[ $section ] ?? array(), $value );
            }
        }

        $custom_css = $request->get_param( 'custom_css' );
        if ( $custom_css !== null ) {
            $current['custom_css'] = wp_strip_all_tags( $custom_css );
        }

        update_option( 'flavor_vbp_design_system', $current );

        // También sincronizar con las opciones legacy para compatibilidad
        $this->sync_design_system_to_legacy( $current );

        return new WP_REST_Response( array(
            'success'       => true,
            'message'       => 'Design system actualizado.',
            'design_system' => $current,
            'css'           => $this->generate_design_system_css( $current ),
        ), 200 );
    }

    /**
     * Genera CSS del design system.
     *
     * @param array $design_system Design system.
     * @return string
     */
    private function generate_design_system_css( $design_system ) {
        $css = ':root {' . "\n";

        // Colores
        if ( ! empty( $design_system['colors'] ) ) {
            foreach ( $design_system['colors'] as $name => $value ) {
                $css .= "  --vbp-color-{$name}: {$value};\n";
            }
        }

        // Tipografía
        if ( ! empty( $design_system['typography'] ) ) {
            $typo = $design_system['typography'];
            if ( ! empty( $typo['font_family'] ) ) {
                $css .= "  --vbp-font-family: {$typo['font_family']};\n";
            }
            if ( ! empty( $typo['heading_font'] ) && $typo['heading_font'] !== 'inherit' ) {
                $css .= "  --vbp-font-heading: {$typo['heading_font']};\n";
            }
            if ( ! empty( $typo['base_size'] ) ) {
                $css .= "  --vbp-font-size-base: {$typo['base_size']};\n";
            }
            if ( ! empty( $typo['line_height'] ) ) {
                $css .= "  --vbp-line-height: {$typo['line_height']};\n";
            }
        }

        // Espaciado
        if ( ! empty( $design_system['spacing'] ) ) {
            foreach ( $design_system['spacing'] as $name => $value ) {
                $css .= "  --vbp-space-{$name}: {$value};\n";
            }
        }

        // Bordes
        if ( ! empty( $design_system['borders'] ) ) {
            foreach ( $design_system['borders'] as $name => $value ) {
                $css_name = str_replace( '_', '-', $name );
                $css .= "  --vbp-{$css_name}: {$value};\n";
            }
        }

        // Sombras
        if ( ! empty( $design_system['shadows'] ) ) {
            foreach ( $design_system['shadows'] as $name => $value ) {
                $css .= "  --vbp-shadow-{$name}: {$value};\n";
            }
        }

        $css .= "}\n";

        // CSS personalizado
        if ( ! empty( $design_system['custom_css'] ) ) {
            $css .= "\n" . $design_system['custom_css'];
        }

        return $css;
    }

    /**
     * Genera output de variables CSS para uso en JS/React.
     *
     * @param array $design_system Design system.
     * @return array
     */
    private function generate_css_variables_output( $design_system ) {
        $variables = array();

        if ( ! empty( $design_system['colors'] ) ) {
            foreach ( $design_system['colors'] as $name => $value ) {
                $variables["--vbp-color-{$name}"] = $value;
            }
        }

        if ( ! empty( $design_system['spacing'] ) ) {
            foreach ( $design_system['spacing'] as $name => $value ) {
                $variables["--vbp-space-{$name}"] = $value;
            }
        }

        if ( ! empty( $design_system['borders'] ) ) {
            foreach ( $design_system['borders'] as $name => $value ) {
                $css_name = str_replace( '_', '-', $name );
                $variables["--vbp-{$css_name}"] = $value;
            }
        }

        return $variables;
    }

    /**
     * Sincroniza design system con opciones legacy para compatibilidad.
     *
     * @param array $design_system Design system.
     */
    private function sync_design_system_to_legacy( $design_system ) {
        // Sincronizar con global-styles
        $global_styles = array(
            'colors'     => $design_system['colors'] ?? array(),
            'typography' => $design_system['typography'] ?? array(),
            'spacing'    => $design_system['spacing'] ?? array(),
            'custom_css' => $design_system['custom_css'] ?? '',
        );
        update_option( 'flavor_vbp_global_styles', $global_styles );

        // Sincronizar con design/variables
        update_option( 'flavor_vbp_design_variables', array(
            'colors'     => $design_system['colors'] ?? array(),
            'spacing'    => $design_system['spacing'] ?? array(),
            'typography' => $design_system['typography'] ?? array(),
            'borders'    => $design_system['borders'] ?? array(),
        ) );
    }

    /**
     * Deep merge de arrays.
     *
     * @param array $array1 Array base.
     * @param array $array2 Array a mergear.
     * @return array
     */
    private function deep_merge_arrays( $array1, $array2 ) {
        $merged = $array1;
        foreach ( $array2 as $key => $value ) {
            if ( is_array( $value ) && isset( $merged[ $key ] ) && is_array( $merged[ $key ] ) ) {
                $merged[ $key ] = $this->deep_merge_arrays( $merged[ $key ], $value );
            } else {
                $merged[ $key ] = $value;
            }
        }
        return $merged;
    }

    // =============================================
    // MÉTODOS DE OPERACIONES EN LOTE
    // =============================================

    /**
     * Publica múltiples páginas
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function bulk_publish_pages( $request ) {
        $page_ids = $request->get_param( 'page_ids' );

        $results = array(
            'success' => array(),
            'failed'  => array(),
        );

        foreach ( $page_ids as $page_id ) {
            $post = get_post( $page_id );
            if ( ! $this->is_valid_vbp_post( $post ) ) {
                $results['failed'][] = array(
                    'id'    => $page_id,
                    'error' => 'Página no encontrada.',
                );
                continue;
            }

            $updated = wp_update_post( array(
                'ID'          => $page_id,
                'post_status' => 'publish',
            ) );

            if ( is_wp_error( $updated ) ) {
                $results['failed'][] = array(
                    'id'    => $page_id,
                    'error' => $updated->get_error_message(),
                );
            } else {
                $results['success'][] = $page_id;
            }
        }

        return new WP_REST_Response( array(
            'success'   => true,
            'published' => count( $results['success'] ),
            'failed'    => count( $results['failed'] ),
            'results'   => $results,
        ), 200 );
    }

    /**
     * Elimina múltiples páginas
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function bulk_delete_pages( $request ) {
        $page_ids = $request->get_param( 'page_ids' );
        $force = (bool) $request->get_param( 'force' );

        $results = array(
            'success' => array(),
            'failed'  => array(),
        );

        foreach ( $page_ids as $page_id ) {
            $post = get_post( $page_id );
            if ( ! $this->is_valid_vbp_post( $post ) ) {
                $results['failed'][] = array(
                    'id'    => $page_id,
                    'error' => 'Página no encontrada.',
                );
                continue;
            }

            $deleted = wp_delete_post( $page_id, $force );

            if ( ! $deleted ) {
                $results['failed'][] = array(
                    'id'    => $page_id,
                    'error' => 'Error al eliminar.',
                );
            } else {
                $results['success'][] = $page_id;
            }
        }

        return new WP_REST_Response( array(
            'success' => true,
            'deleted' => count( $results['success'] ),
            'failed'  => count( $results['failed'] ),
            'force'   => $force,
            'results' => $results,
        ), 200 );
    }

    /**
     * Duplica múltiples páginas
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function bulk_duplicate_pages( $request ) {
        $page_ids = $request->get_param( 'page_ids' );

        $results = array(
            'success' => array(),
            'failed'  => array(),
        );

        foreach ( $page_ids as $page_id ) {
            // Crear request para duplicar
            $dup_request = new WP_REST_Request( 'POST' );
            $dup_request->set_param( 'id', $page_id );
            $dup_request->set_param( 'status', 'draft' );

            $response = $this->duplicate_page( $dup_request );
            $data = $response->get_data();

            if ( ! empty( $data['success'] ) ) {
                $results['success'][] = array(
                    'original_id' => $page_id,
                    'new_id'      => $data['id'],
                );
            } else {
                $results['failed'][] = array(
                    'id'    => $page_id,
                    'error' => $data['error'] ?? 'Error desconocido.',
                );
            }
        }

        return new WP_REST_Response( array(
            'success'    => true,
            'duplicated' => count( $results['success'] ),
            'failed'     => count( $results['failed'] ),
            'results'    => $results,
        ), 200 );
    }

    /**
     * Asigna etiquetas a múltiples páginas
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function bulk_set_tags( $request ) {
        $page_ids = $request->get_param( 'page_ids' );
        $tags = $request->get_param( 'tags' );
        $mode = $request->get_param( 'mode' );

        $clean_tags = array_map( 'sanitize_text_field', $tags );
        $clean_tags = array_filter( $clean_tags );

        $results = array(
            'success' => array(),
            'failed'  => array(),
        );

        foreach ( $page_ids as $page_id ) {
            $post = get_post( $page_id );
            if ( ! $this->is_valid_vbp_post( $post ) ) {
                $results['failed'][] = $page_id;
                continue;
            }

            $current_tags_json = get_post_meta( $page_id, '_flavor_vbp_tags', true );
            $current_tags = $current_tags_json ? json_decode( $current_tags_json, true ) : array();

            switch ( $mode ) {
                case 'replace':
                    $new_tags = $clean_tags;
                    break;
                case 'remove':
                    $new_tags = array_diff( $current_tags, $clean_tags );
                    break;
                case 'add':
                default:
                    $new_tags = array_unique( array_merge( $current_tags, $clean_tags ) );
                    break;
            }

            update_post_meta( $page_id, '_flavor_vbp_tags', wp_json_encode( array_values( $new_tags ) ) );
            $results['success'][] = $page_id;
        }

        return new WP_REST_Response( array(
            'success'  => true,
            'mode'     => $mode,
            'tags'     => $clean_tags,
            'updated'  => count( $results['success'] ),
            'failed'   => count( $results['failed'] ),
            'results'  => $results,
        ), 200 );
    }

    // =============================================
    // MÉTODOS DE PROGRAMACIÓN
    // =============================================

    /**
     * Programa publicación de una página
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function schedule_page( $request ) {
        $page_id = (int) $request->get_param( 'id' );
        $publish_date = $request->get_param( 'publish_date' );

        $post = get_post( $page_id );
        if ( ! $this->is_valid_vbp_post( $post ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Página no encontrada.',
            ), 404 );
        }

        // Validar fecha
        $timestamp = strtotime( $publish_date );
        if ( ! $timestamp || $timestamp <= time() ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'La fecha debe ser futura.',
            ), 400 );
        }

        $gmt_date = gmdate( 'Y-m-d H:i:s', $timestamp );
        $local_date = date( 'Y-m-d H:i:s', $timestamp );

        $updated = wp_update_post( array(
            'ID'            => $page_id,
            'post_status'   => 'future',
            'post_date'     => $local_date,
            'post_date_gmt' => $gmt_date,
        ) );

        if ( is_wp_error( $updated ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => $updated->get_error_message(),
            ), 500 );
        }

        return new WP_REST_Response( array(
            'success'      => true,
            'message'      => 'Página programada.',
            'page_id'      => $page_id,
            'publish_date' => $local_date,
            'publish_gmt'  => $gmt_date,
        ), 200 );
    }

    /**
     * Cancela programación
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function unschedule_page( $request ) {
        $page_id = (int) $request->get_param( 'id' );

        $post = get_post( $page_id );
        if ( ! $this->is_valid_vbp_post( $post ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'Página no encontrada.',
            ), 404 );
        }

        if ( $post->post_status !== 'future' ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => 'La página no está programada.',
            ), 400 );
        }

        $updated = wp_update_post( array(
            'ID'          => $page_id,
            'post_status' => 'draft',
        ) );

        if ( is_wp_error( $updated ) ) {
            return new WP_REST_Response( array(
                'success' => false,
                'error'   => $updated->get_error_message(),
            ), 500 );
        }

        return new WP_REST_Response( array(
            'success' => true,
            'message' => 'Programación cancelada.',
            'page_id' => $page_id,
            'status'  => 'draft',
        ), 200 );
    }

    /**
     * Lista páginas programadas
     *
     * @param WP_REST_Request $request Petición REST.
     * @return WP_REST_Response
     */
    public function list_scheduled_pages( $request ) {
        $pages = get_posts( array(
            'post_type'      => 'flavor_landing',
            'post_status'    => 'future',
            'posts_per_page' => flavor_safe_posts_limit( -1 ),
            'orderby'        => 'date',
            'order'          => 'ASC',
        ) );

        $scheduled = array();
        foreach ( $pages as $page ) {
            $scheduled[] = array(
                'id'           => $page->ID,
                'title'        => $page->post_title,
                'publish_date' => $page->post_date,
                'publish_gmt'  => $page->post_date_gmt,
                'time_until'   => human_time_diff( time(), strtotime( $page->post_date ) ),
                'edit_url'     => admin_url( "admin.php?page=vbp-editor&post_id={$page->ID}" ),
            );
        }

        return new WP_REST_Response( array(
            'success' => true,
            'total'   => count( $scheduled ),
            'pages'   => $scheduled,
        ), 200 );
    }

