                'error'   => 'Widget no encontrado.',
            ), 404 );
        }

        $widgets[ $widget_id ]['variables'] = $variables;
        update_option( 'flavor_vbp_global_widgets', $widgets );

        return new WP_REST_Response( array(
            'success' => true,
            'message' => 'Variables configuradas.',
        ), 200 );
    }

