    private function generate_pdf_html( $post, $elements, $include_notes ) {
        $title = esc_html( $post->post_title );
        $date = date_i18n( get_option( 'date_format' ), strtotime( $post->post_modified ) );
        $content = $this->elements_to_html( $elements );

        $notes_html = '';
