            $notes = get_post_meta( $post->ID, '_vbp_review_comments', true ) ?: array();
            if ( ! empty( $notes ) ) {
                $notes_html = '<div class="pdf-notes"><h2>Notas de Revisión</h2><ul>';
                foreach ( $notes as $note ) {
                    $notes_html .= '<li>' . esc_html( $note['content'] ?? '' ) . '</li>';
                }
                $notes_html .= '</ul></div>';
            }
        }

        return "<!DOCTYPE html>
<html lang=\"es\">
<head>
